window.BIBLE["2Corinthians"] = {"1":{"chapter":"1","title":"THE GOD OF ALL COMFORT","verses":{"1":{"text":"Paul, an apostle of Jesus Christ by the will of God, and Timothy our brother, unto the church of God which is at Corinth, with all the saints which are in all Achaia:","ref":"2 Corinthians 1:1","synthesized":"Paul, an apostle of Jesus Christ by the will of God, and Timothy our brother, unto the church of God which is at Corinth, with all the saints which are in all Achaia:","sources":{"KJV":{"text":"Paul, an apostle of Jesus Christ by the will of God, and Timothy our brother, unto the church of God which is at Corinth, with all the saints which are in all Achaia:"}},"definableWords":["God","brother"],"peopleInVerse":["Paul","Jesus"]},"2":{"text":"Grace be to you and peace from God our Father, and from the Lord Jesus Christ.","ref":"2 Corinthians 1:2","synthesized":"Grace be to you and peace from God our Father, and from the Lord Jesus Christ.","sources":{"KJV":{"text":"Grace be to you and peace from God our Father, and from the Lord Jesus Christ."}},"definableWords":["peace","God","father","Lord"],"peopleInVerse":["Jesus"]},"3":{"text":"Blessed be God, even the Father of our Lord Jesus Christ, the Father of mercies, and the God of all comfort;","ref":"2 Corinthians 1:3","synthesized":"Blessed be God, even the Father of our Lord Jesus Christ, the Father of mercies, and the God of all comfort;","sources":{"KJV":{"text":"Blessed be God, even the Father of our Lord Jesus Christ, the Father of mercies, and the God of all comfort;"}},"definableWords":["blessed","God","father","Lord"],"peopleInVerse":["Jesus"]},"4":{"text":"Who comforteth us in all our tribulation, that we may be able to comfort them which are in any trouble, by the comfort wherewith we ourselves are comforted of God.","ref":"2 Corinthians 1:4","synthesized":"Who comforteth us in all our tribulation, that we may be able to comfort them which are in any trouble, by the comfort wherewith we ourselves are comforted of God.","sources":{"KJV":{"text":"Who comforteth us in all our tribulation, that we may be able to comfort them which are in any trouble, by the comfort wherewith we ourselves are comforted of God."}},"definableWords":["God"],"peopleInVerse":[]},"5":{"text":"For as the sufferings of Christ abound in us, so our consolation also aboundeth by Christ.","ref":"2 Corinthians 1:5","synthesized":"For as the sufferings of Christ abound in us, so our consolation also aboundeth by Christ.","sources":{"KJV":{"text":"For as the sufferings of Christ abound in us, so our consolation also aboundeth by Christ."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"And whether we be afflicted, it is for your consolation and salvation, which is effectual in the enduring of the same sufferings which we also suffer: or whether we be comforted, it is for your consolation and salvation.","ref":"2 Corinthians 1:6","synthesized":"And whether we be afflicted, it is for your consolation and salvation, which is effectual in the enduring of the same sufferings which we also suffer: or whether we be comforted, it is for your consolation and salvation.","sources":{"KJV":{"text":"And whether we be afflicted, it is for your consolation and salvation, which is effectual in the enduring of the same sufferings which we also suffer: or whether we be comforted, it is for your consolation and salvation."}},"definableWords":["or"],"peopleInVerse":[]},"7":{"text":"And our hope of you is stedfast, knowing, that as ye are partakers of the sufferings, so shall ye be also of the consolation.","ref":"2 Corinthians 1:7","synthesized":"And our hope of you is stedfast, knowing, that as ye are partakers of the sufferings, so shall ye be also of the consolation.","sources":{"KJV":{"text":"And our hope of you is stedfast, knowing, that as ye are partakers of the sufferings, so shall ye be also of the consolation."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For we would not, brethren, have you ignorant of our trouble which came to us in Asia, that we were pressed out of measure, above strength, insomuch that we despaired even of life:","ref":"2 Corinthians 1:8","synthesized":"For we would not, brethren, have you ignorant of our trouble which came to us in Asia, that we were pressed out of measure, above strength, insomuch that we despaired even of life:","sources":{"KJV":{"text":"For we would not, brethren, have you ignorant of our trouble which came to us in Asia, that we were pressed out of measure, above strength, insomuch that we despaired even of life:"}},"definableWords":["brethren","life"],"peopleInVerse":[]},"9":{"text":"But we had the sentence of death in ourselves, that we should not trust in ourselves, but in God which raiseth the dead:","ref":"2 Corinthians 1:9","synthesized":"But we had the sentence of death in ourselves, that we should not trust in ourselves, but in God which raiseth the dead:","sources":{"KJV":{"text":"But we had the sentence of death in ourselves, that we should not trust in ourselves, but in God which raiseth the dead:"}},"definableWords":["death","God"],"peopleInVerse":[]},"10":{"text":"Who delivered us from so great a death, and doth deliver: in whom we trust that he will yet deliver us;","ref":"2 Corinthians 1:10","synthesized":"Who delivered us from so great a death, and doth deliver: in whom we trust that he will yet deliver us;","sources":{"KJV":{"text":"Who delivered us from so great a death, and doth deliver: in whom we trust that he will yet deliver us;"}},"definableWords":["great","death"],"peopleInVerse":[]},"11":{"text":"Ye also helping together by prayer for us, that for the gift bestowed upon us by the means of many persons thanks may be given by many on our behalf.","ref":"2 Corinthians 1:11","synthesized":"Ye also helping together by prayer for us, that for the gift bestowed upon us by the means of many persons thanks may be given by many on our behalf.","sources":{"KJV":{"text":"Ye also helping together by prayer for us, that for the gift bestowed upon us by the means of many persons thanks may be given by many on our behalf."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For our rejoicing is this, the testimony of our conscience, that in simplicity and godly sincerity, not with fleshly wisdom, but by the grace of God, we have had our conversation in the world, and more abundantly to you-ward.","ref":"2 Corinthians 1:12","synthesized":"For our rejoicing is this, the testimony of our conscience, that in simplicity and godly sincerity, not with fleshly wisdom, but by the grace of God, we have had our conversation in the world, and more abundantly to you-ward.","sources":{"KJV":{"text":"For our rejoicing is this, the testimony of our conscience, that in simplicity and godly sincerity, not with fleshly wisdom, but by the grace of God, we have had our conversation in the world, and more abundantly to you-ward."}},"definableWords":["wisdom","God"],"peopleInVerse":[]},"13":{"text":"For we write none other things unto you, than what ye read or acknowledge; and I trust ye shall acknowledge even to the end;","ref":"2 Corinthians 1:13","synthesized":"For we write none other things unto you, than what ye read or acknowledge; and I trust ye shall acknowledge even to the end;","sources":{"KJV":{"text":"For we write none other things unto you, than what ye read or acknowledge; and I trust ye shall acknowledge even to the end;"}},"definableWords":["or"],"peopleInVerse":[]},"14":{"text":"As also ye have acknowledged us in part, that we are your rejoicing, even as ye also are ours in the day of the Lord Jesus.","ref":"2 Corinthians 1:14","synthesized":"As also ye have acknowledged us in part, that we are your rejoicing, even as ye also are ours in the day of the Lord Jesus.","sources":{"KJV":{"text":"As also ye have acknowledged us in part, that we are your rejoicing, even as ye also are ours in the day of the Lord Jesus."}},"definableWords":["day","Lord"],"peopleInVerse":["Jesus"]},"15":{"text":"And in this confidence I was minded to come unto you before, that ye might have a second benefit;","ref":"2 Corinthians 1:15","synthesized":"And in this confidence I was minded to come unto you before, that ye might have a second benefit;","sources":{"KJV":{"text":"And in this confidence I was minded to come unto you before, that ye might have a second benefit;"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"And to pass by you into Macedonia, and to come again out of Macedonia unto you, and of you to be brought on my way toward Judaea.","ref":"2 Corinthians 1:16","synthesized":"And to pass by you into Macedonia, and to come again out of Macedonia unto you, and of you to be brought on my way toward Judaea.","sources":{"KJV":{"text":"And to pass by you into Macedonia, and to come again out of Macedonia unto you, and of you to be brought on my way toward Judaea."}},"definableWords":["way"],"peopleInVerse":[]},"17":{"text":"When I therefore was thus minded, did I use lightness? or the things that I purpose, do I purpose according to the flesh, that with me there should be yea yea, and nay nay?","ref":"2 Corinthians 1:17","synthesized":"When I therefore was thus minded, did I use lightness? or the things that I purpose, do I purpose according to the flesh, that with me there should be yea yea, and nay nay?","sources":{"KJV":{"text":"When I therefore was thus minded, did I use lightness? or the things that I purpose, do I purpose according to the flesh, that with me there should be yea yea, and nay nay?"}},"definableWords":["or","flesh"],"peopleInVerse":[]},"18":{"text":"But as God is true, our word toward you was not yea and nay.","ref":"2 Corinthians 1:18","synthesized":"But as God is true, our word toward you was not yea and nay.","sources":{"KJV":{"text":"But as God is true, our word toward you was not yea and nay."}},"definableWords":["God","word"],"peopleInVerse":[]},"19":{"text":"For the Son of God, Jesus Christ, who was preached among you by us, even by me and Silvanus and Timotheus, was not yea and nay, but in him was yea.","ref":"2 Corinthians 1:19","synthesized":"For the Son of God, Jesus Christ, who was preached among you by us, even by me and Silvanus and Timotheus, was not yea and nay, but in him was yea.","sources":{"KJV":{"text":"For the Son of God, Jesus Christ, who was preached among you by us, even by me and Silvanus and Timotheus, was not yea and nay, but in him was yea."}},"definableWords":["son","God"],"peopleInVerse":["Jesus"]},"20":{"text":"For all the promises of God in him are yea, and in him Amen, unto the glory of God by us.","ref":"2 Corinthians 1:20","synthesized":"For all the promises of God in him are yea, and in him Amen, unto the glory of God by us.","sources":{"KJV":{"text":"For all the promises of God in him are yea, and in him Amen, unto the glory of God by us."}},"definableWords":["God"],"peopleInVerse":[]},"21":{"text":"Now he which stablisheth us with you in Christ, and hath anointed us, is God;","ref":"2 Corinthians 1:21","synthesized":"Now he which stablisheth us with you in Christ, and hath anointed us, is God;","sources":{"KJV":{"text":"Now he which stablisheth us with you in Christ, and hath anointed us, is God;"}},"definableWords":["God"],"peopleInVerse":[]},"22":{"text":"Who hath also sealed us, and given the earnest of the Spirit in our hearts.","ref":"2 Corinthians 1:22","synthesized":"Who hath also sealed us, and given the earnest of the Spirit in our hearts.","sources":{"KJV":{"text":"Who hath also sealed us, and given the earnest of the Spirit in our hearts."}},"definableWords":["Spirit"],"peopleInVerse":[]},"23":{"text":"Moreover I call God for a record upon my soul, that to spare you I came not as yet unto Corinth.","ref":"2 Corinthians 1:23","synthesized":"Moreover I call God for a record upon my soul, that to spare you I came not as yet unto Corinth.","sources":{"KJV":{"text":"Moreover I call God for a record upon my soul, that to spare you I came not as yet unto Corinth."}},"definableWords":["God","soul"],"peopleInVerse":[]},"24":{"text":"Not for that we have dominion over your faith, but are helpers of your joy: for by faith ye stand.","ref":"2 Corinthians 1:24","synthesized":"Not for that we have dominion over your faith, but are helpers of your joy: for by faith ye stand.","sources":{"KJV":{"text":"Not for that we have dominion over your faith, but are helpers of your joy: for by faith ye stand."}},"definableWords":["dominion","faith"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"FORGIVE THE OFFENDER","verses":{"1":{"text":"But I determined this with myself, that I would not come again to you in heaviness.","ref":"2 Corinthians 2:1","synthesized":"But I determined this with myself, that I would not come again to you in heaviness.","sources":{"KJV":{"text":"But I determined this with myself, that I would not come again to you in heaviness."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"For if I make you sorry, who is he then that maketh me glad, but the same which is made sorry by me?","ref":"2 Corinthians 2:2","synthesized":"For if I make you sorry, who is he then that maketh me glad, but the same which is made sorry by me?","sources":{"KJV":{"text":"For if I make you sorry, who is he then that maketh me glad, but the same which is made sorry by me?"}},"definableWords":["make","made"],"peopleInVerse":[]},"3":{"text":"And I wrote this same unto you, lest, when I came, I should have sorrow from them of whom I ought to rejoice; having confidence in you all, that my joy is the joy of you all.","ref":"2 Corinthians 2:3","synthesized":"And I wrote this same unto you, lest, when I came, I should have sorrow from them of whom I ought to rejoice; having confidence in you all, that my joy is the joy of you all.","sources":{"KJV":{"text":"And I wrote this same unto you, lest, when I came, I should have sorrow from them of whom I ought to rejoice; having confidence in you all, that my joy is the joy of you all."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"For out of much affliction and anguish of heart I wrote unto you with many tears; not that ye should be grieved, but that ye might know the love which I have more abundantly unto you.","ref":"2 Corinthians 2:4","synthesized":"For out of much affliction and anguish of heart I wrote unto you with many tears; not that ye should be grieved, but that ye might know the love which I have more abundantly unto you.","sources":{"KJV":{"text":"For out of much affliction and anguish of heart I wrote unto you with many tears; not that ye should be grieved, but that ye might know the love which I have more abundantly unto you."}},"definableWords":["love"],"peopleInVerse":[]},"5":{"text":"But if any have caused grief, he hath not grieved me, but in part: that I may not overcharge you all.","ref":"2 Corinthians 2:5","synthesized":"But if any have caused grief, he hath not grieved me, but in part: that I may not overcharge you all.","sources":{"KJV":{"text":"But if any have caused grief, he hath not grieved me, but in part: that I may not overcharge you all."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Sufficient to such a man is this punishment, which was inflicted of many.","ref":"2 Corinthians 2:6","synthesized":"Sufficient to such a man is this punishment, which was inflicted of many.","sources":{"KJV":{"text":"Sufficient to such a man is this punishment, which was inflicted of many."}},"definableWords":["man"],"peopleInVerse":[]},"7":{"text":"So that contrariwise ye ought rather to forgive him, and comfort him, lest perhaps such a one should be swallowed up with overmuch sorrow.","ref":"2 Corinthians 2:7","synthesized":"So that contrariwise ye ought rather to forgive him, and comfort him, lest perhaps such a one should be swallowed up with overmuch sorrow.","sources":{"KJV":{"text":"So that contrariwise ye ought rather to forgive him, and comfort him, lest perhaps such a one should be swallowed up with overmuch sorrow."}},"definableWords":["one"],"peopleInVerse":[]},"8":{"text":"Wherefore I beseech you that ye would confirm your love toward him.","ref":"2 Corinthians 2:8","synthesized":"Wherefore I beseech you that ye would confirm your love toward him.","sources":{"KJV":{"text":"Wherefore I beseech you that ye would confirm your love toward him."}},"definableWords":["love"],"peopleInVerse":[]},"9":{"text":"For to this end also did I write, that I might know the proof of you, whether ye be obedient in all things.","ref":"2 Corinthians 2:9","synthesized":"For to this end also did I write, that I might know the proof of you, whether ye be obedient in all things.","sources":{"KJV":{"text":"For to this end also did I write, that I might know the proof of you, whether ye be obedient in all things."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"To whom ye forgive any thing, I forgive also: for if I forgave any thing, to whom I forgave it, for your sakes forgave I it in the person of Christ;","ref":"2 Corinthians 2:10","synthesized":"To whom ye forgive any thing, I forgive also: for if I forgave any thing, to whom I forgave it, for your sakes forgave I it in the person of Christ;","sources":{"KJV":{"text":"To whom ye forgive any thing, I forgive also: for if I forgave any thing, to whom I forgave it, for your sakes forgave I it in the person of Christ;"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Lest Satan should get an advantage of us: for we are not ignorant of his devices.","ref":"2 Corinthians 2:11","synthesized":"Lest Satan should get an advantage of us: for we are not ignorant of his devices.","sources":{"KJV":{"text":"Lest Satan should get an advantage of us: for we are not ignorant of his devices."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Furthermore, when I came to Troas to preach Christ’s gospel, and a door was opened unto me of the Lord,","ref":"2 Corinthians 2:12","synthesized":"Furthermore, when I came to Troas to preach Christ’s gospel, and a door was opened unto me of the Lord,","sources":{"KJV":{"text":"Furthermore, when I came to Troas to preach Christ’s gospel, and a door was opened unto me of the Lord,"}},"definableWords":["Lord"],"peopleInVerse":[]},"13":{"text":"I had no rest in my spirit, because I found not Titus my brother: but taking my leave of them, I went from thence into Macedonia.","ref":"2 Corinthians 2:13","synthesized":"I had no rest in my spirit, because I found not Titus my brother: but taking my leave of them, I went from thence into Macedonia.","sources":{"KJV":{"text":"I had no rest in my spirit, because I found not Titus my brother: but taking my leave of them, I went from thence into Macedonia."}},"definableWords":["rest","spirit","brother"],"peopleInVerse":[]},"14":{"text":"Now thanks be unto God, which always causeth us to triumph in Christ, and maketh manifest the savour of his knowledge by us in every place.","ref":"2 Corinthians 2:14","synthesized":"Now thanks be unto God, which always causeth us to triumph in Christ, and maketh manifest the savour of his knowledge by us in every place.","sources":{"KJV":{"text":"Now thanks be unto God, which always causeth us to triumph in Christ, and maketh manifest the savour of his knowledge by us in every place."}},"definableWords":["God","knowledge"],"peopleInVerse":[]},"15":{"text":"For we are unto God a sweet savour of Christ, in them that are saved, and in them that perish:","ref":"2 Corinthians 2:15","synthesized":"For we are unto God a sweet savour of Christ, in them that are saved, and in them that perish:","sources":{"KJV":{"text":"For we are unto God a sweet savour of Christ, in them that are saved, and in them that perish:"}},"definableWords":["God"],"peopleInVerse":[]},"16":{"text":"To the one we are the savour of death unto death; and to the other the savour of life unto life. And who is sufficient for these things?","ref":"2 Corinthians 2:16","synthesized":"To the one we are the savour of death unto death; and to the other the savour of life unto life. And who is sufficient for these things?","sources":{"KJV":{"text":"To the one we are the savour of death unto death; and to the other the savour of life unto life. And who is sufficient for these things?"}},"definableWords":["one","death","life"],"peopleInVerse":[]},"17":{"text":"For we are not as many, which corrupt the word of God: but as of sincerity, but as of God, in the sight of God speak we in Christ.","ref":"2 Corinthians 2:17","synthesized":"For we are not as many, which corrupt the word of God: but as of sincerity, but as of God, in the sight of God speak we in Christ.","sources":{"KJV":{"text":"For we are not as many, which corrupt the word of God: but as of sincerity, but as of God, in the sight of God speak we in Christ."}},"definableWords":["word","God"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"EPISTLE WRITTEN IN OUR HEARTS","verses":{"1":{"text":"Do we begin again to commend ourselves? or need we, as some others, epistles of commendation to you, or letters of commendation from you?","ref":"2 Corinthians 3:1","synthesized":"Do we begin again to commend ourselves? or need we, as some others, epistles of commendation to you, or letters of commendation from you?","sources":{"KJV":{"text":"Do we begin again to commend ourselves? or need we, as some others, epistles of commendation to you, or letters of commendation from you?"}},"definableWords":["begin","or"],"peopleInVerse":[]},"2":{"text":"Ye are our epistle written in our hearts, known and read of all men:","ref":"2 Corinthians 3:2","synthesized":"Ye are our epistle written in our hearts, known and read of all men:","sources":{"KJV":{"text":"Ye are our epistle written in our hearts, known and read of all men:"}},"definableWords":["men"],"peopleInVerse":[]},"3":{"text":"Forasmuch as ye are manifestly declared to be the epistle of Christ ministered by us, written not with ink, but with the Spirit of the living God; not in tables of stone, but in fleshy tables of the heart.","ref":"2 Corinthians 3:3","synthesized":"Forasmuch as ye are manifestly declared to be the epistle of Christ ministered by us, written not with ink, but with the Spirit of the living God; not in tables of stone, but in fleshy tables of the heart.","sources":{"KJV":{"text":"Forasmuch as ye are manifestly declared to be the epistle of Christ ministered by us, written not with ink, but with the Spirit of the living God; not in tables of stone, but in fleshy tables of the heart."}},"definableWords":["Spirit","living","God","stone"],"peopleInVerse":[]},"4":{"text":"And such trust have we through Christ to God-ward:","ref":"2 Corinthians 3:4","synthesized":"And such trust have we through Christ to God-ward:","sources":{"KJV":{"text":"And such trust have we through Christ to God-ward:"}},"definableWords":["God"],"peopleInVerse":[]},"5":{"text":"Not that we are sufficient of ourselves to think any thing as of ourselves; but our sufficiency is of God;","ref":"2 Corinthians 3:5","synthesized":"Not that we are sufficient of ourselves to think any thing as of ourselves; but our sufficiency is of God;","sources":{"KJV":{"text":"Not that we are sufficient of ourselves to think any thing as of ourselves; but our sufficiency is of God;"}},"definableWords":["God"],"peopleInVerse":[]},"6":{"text":"Who also hath made us able ministers of the new testament; not of the letter, but of the spirit: for the letter killeth, but the spirit giveth life.","ref":"2 Corinthians 3:6","synthesized":"Who also hath made us able ministers of the new testament; not of the letter, but of the spirit: for the letter killeth, but the spirit giveth life.","sources":{"KJV":{"text":"Who also hath made us able ministers of the new testament; not of the letter, but of the spirit: for the letter killeth, but the spirit giveth life."}},"definableWords":["made","spirit","life"],"peopleInVerse":[]},"7":{"text":"But if the ministration of death, written and engraven in stones, was glorious, so that the children of Israel could not stedfastly behold the face of Moses for the glory of his countenance; which glory was to be done away:","ref":"2 Corinthians 3:7","synthesized":"But if the ministration of death, written and engraven in stones, was glorious, so that the children of Israel could not stedfastly behold the face of Moses for the glory of his countenance; which glory was to be done away:","sources":{"KJV":{"text":"But if the ministration of death, written and engraven in stones, was glorious, so that the children of Israel could not stedfastly behold the face of Moses for the glory of his countenance; which glory was to be done away:"}},"definableWords":["death","Israel"],"peopleInVerse":["Moses"]},"8":{"text":"How shall not the ministration of the spirit be rather glorious?","ref":"2 Corinthians 3:8","synthesized":"How shall not the ministration of the spirit be rather glorious?","sources":{"KJV":{"text":"How shall not the ministration of the spirit be rather glorious?"}},"definableWords":["spirit"],"peopleInVerse":[]},"9":{"text":"For if the ministration of condemnation be glory, much more doth the ministration of righteousness exceed in glory.","ref":"2 Corinthians 3:9","synthesized":"For if the ministration of condemnation be glory, much more doth the ministration of righteousness exceed in glory.","sources":{"KJV":{"text":"For if the ministration of condemnation be glory, much more doth the ministration of righteousness exceed in glory."}},"definableWords":["righteousness"],"peopleInVerse":[]},"10":{"text":"For even that which was made glorious had no glory in this respect, by reason of the glory that excelleth.","ref":"2 Corinthians 3:10","synthesized":"For even that which was made glorious had no glory in this respect, by reason of the glory that excelleth.","sources":{"KJV":{"text":"For even that which was made glorious had no glory in this respect, by reason of the glory that excelleth."}},"definableWords":["made"],"peopleInVerse":[]},"11":{"text":"For if that which is done away was glorious, much more that which remaineth is glorious.","ref":"2 Corinthians 3:11","synthesized":"For if that which is done away was glorious, much more that which remaineth is glorious.","sources":{"KJV":{"text":"For if that which is done away was glorious, much more that which remaineth is glorious."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Seeing then that we have such hope, we use great plainness of speech:","ref":"2 Corinthians 3:12","synthesized":"Seeing then that we have such hope, we use great plainness of speech:","sources":{"KJV":{"text":"Seeing then that we have such hope, we use great plainness of speech:"}},"definableWords":["great"],"peopleInVerse":[]},"13":{"text":"And not as Moses, which put a vail over his face, that the children of Israel could not stedfastly look to the end of that which is abolished:","ref":"2 Corinthians 3:13","synthesized":"And not as Moses, which put a vail over his face, that the children of Israel could not stedfastly look to the end of that which is abolished:","sources":{"KJV":{"text":"And not as Moses, which put a vail over his face, that the children of Israel could not stedfastly look to the end of that which is abolished:"}},"definableWords":["Israel"],"peopleInVerse":["Moses"]},"14":{"text":"But their minds were blinded: for until this day remaineth the same vail untaken away in the reading of the old testament; which vail is done away in Christ.","ref":"2 Corinthians 3:14","synthesized":"But their minds were blinded: for until this day remaineth the same vail untaken away in the reading of the old testament; which vail is done away in Christ.","sources":{"KJV":{"text":"But their minds were blinded: for until this day remaineth the same vail untaken away in the reading of the old testament; which vail is done away in Christ."}},"definableWords":["day"],"peopleInVerse":[]},"15":{"text":"But even unto this day, when Moses is read, the vail is upon their heart.","ref":"2 Corinthians 3:15","synthesized":"But even unto this day, when Moses is read, the vail is upon their heart.","sources":{"KJV":{"text":"But even unto this day, when Moses is read, the vail is upon their heart."}},"definableWords":["day"],"peopleInVerse":["Moses"]},"16":{"text":"Nevertheless when it shall turn to the Lord, the vail shall be taken away.","ref":"2 Corinthians 3:16","synthesized":"Nevertheless when it shall turn to the Lord, the vail shall be taken away.","sources":{"KJV":{"text":"Nevertheless when it shall turn to the Lord, the vail shall be taken away."}},"definableWords":["Lord"],"peopleInVerse":[]},"17":{"text":"Now the Lord is that Spirit: and where the Spirit of the Lord is, there is liberty.","ref":"2 Corinthians 3:17","synthesized":"Now the Lord is that Spirit: and where the Spirit of the Lord is, there is liberty.","sources":{"KJV":{"text":"Now the Lord is that Spirit: and where the Spirit of the Lord is, there is liberty."}},"definableWords":["Lord","Spirit","spirit"],"peopleInVerse":[]},"18":{"text":"But we all, with open face beholding as in a glass the glory of the Lord, are changed into the same image from glory to glory, even as by the Spirit of the LORD.","ref":"2 Corinthians 3:18","synthesized":"But we all, with open face beholding as in a glass the glory of the Lord, are changed into the same image from glory to glory, even as by the Spirit of the LORD.","sources":{"KJV":{"text":"But we all, with open face beholding as in a glass the glory of the Lord, are changed into the same image from glory to glory, even as by the Spirit of the LORD."}},"definableWords":["Lord","image","Spirit","LORD"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"TREASURE IN EARTHEN VESSELS","verses":{"1":{"text":"Therefore seeing we have this ministry, as we have received mercy, we faint not;","ref":"2 Corinthians 4:1","synthesized":"Therefore seeing we have this ministry, as we have received mercy, we faint not;","sources":{"KJV":{"text":"Therefore seeing we have this ministry, as we have received mercy, we faint not;"}},"definableWords":["mercy"],"peopleInVerse":[]},"2":{"text":"But have renounced the hidden things of dishonesty, not walking in craftiness, nor handling the word of God deceitfully; but by manifestation of the truth commending ourselves to every man’s conscience in the sight of God.","ref":"2 Corinthians 4:2","synthesized":"But have renounced the hidden things of dishonesty, not walking in craftiness, nor handling the word of God deceitfully; but by manifestation of the truth commending ourselves to every man’s conscience in the sight of God.","sources":{"KJV":{"text":"But have renounced the hidden things of dishonesty, not walking in craftiness, nor handling the word of God deceitfully; but by manifestation of the truth commending ourselves to every man’s conscience in the sight of God."}},"definableWords":["word","God","man"],"peopleInVerse":[]},"3":{"text":"But if our gospel be hid, it is hid to them that are lost:","ref":"2 Corinthians 4:3","synthesized":"But if our gospel be hid, it is hid to them that are lost:","sources":{"KJV":{"text":"But if our gospel be hid, it is hid to them that are lost:"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"In whom the god of this world hath blinded the minds of them which believe not, lest the light of the glorious gospel of Christ, who is the image of God, should shine unto them.","ref":"2 Corinthians 4:4","synthesized":"In whom the god of this world hath blinded the minds of them which believe not, lest the light of the glorious gospel of Christ, who is the image of God, should shine unto them.","sources":{"KJV":{"text":"In whom the god of this world hath blinded the minds of them which believe not, lest the light of the glorious gospel of Christ, who is the image of God, should shine unto them."}},"definableWords":["God","light","image"],"peopleInVerse":[]},"5":{"text":"For we preach not ourselves, but Christ Jesus the Lord; and ourselves your servants for Jesus’ sake.","ref":"2 Corinthians 4:5","synthesized":"For we preach not ourselves, but Christ Jesus the Lord; and ourselves your servants for Jesus’ sake.","sources":{"KJV":{"text":"For we preach not ourselves, but Christ Jesus the Lord; and ourselves your servants for Jesus’ sake."}},"definableWords":["Lord","servants"],"peopleInVerse":["Jesus"]},"6":{"text":"For God, who commanded the light to shine out of darkness, hath shined in our hearts, to give the light of the knowledge of the glory of God in the face of Jesus Christ.","ref":"2 Corinthians 4:6","synthesized":"For God, who commanded the light to shine out of darkness, hath shined in our hearts, to give the light of the knowledge of the glory of God in the face of Jesus Christ.","sources":{"KJV":{"text":"For God, who commanded the light to shine out of darkness, hath shined in our hearts, to give the light of the knowledge of the glory of God in the face of Jesus Christ."}},"definableWords":["God","light","darkness","knowledge"],"peopleInVerse":["Jesus"]},"7":{"text":"But we have this treasure in earthen vessels, that the excellency of the power may be of God, and not of us.","ref":"2 Corinthians 4:7","synthesized":"But we have this treasure in earthen vessels, that the excellency of the power may be of God, and not of us.","sources":{"KJV":{"text":"But we have this treasure in earthen vessels, that the excellency of the power may be of God, and not of us."}},"definableWords":["God"],"peopleInVerse":[]},"8":{"text":"We are troubled on every side, yet not distressed; we are perplexed, but not in despair;","ref":"2 Corinthians 4:8","synthesized":"We are troubled on every side, yet not distressed; we are perplexed, but not in despair;","sources":{"KJV":{"text":"We are troubled on every side, yet not distressed; we are perplexed, but not in despair;"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Persecuted, but not forsaken; cast down, but not destroyed;","ref":"2 Corinthians 4:9","synthesized":"Persecuted, but not forsaken; cast down, but not destroyed;","sources":{"KJV":{"text":"Persecuted, but not forsaken; cast down, but not destroyed;"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Always bearing about in the body the dying of the Lord Jesus, that the life also of Jesus might be made manifest in our body.","ref":"2 Corinthians 4:10","synthesized":"Always bearing about in the body the dying of the Lord Jesus, that the life also of Jesus might be made manifest in our body.","sources":{"KJV":{"text":"Always bearing about in the body the dying of the Lord Jesus, that the life also of Jesus might be made manifest in our body."}},"definableWords":["Lord","life","made"],"peopleInVerse":["Jesus"]},"11":{"text":"For we which live are alway delivered unto death for Jesus’ sake, that the life also of Jesus might be made manifest in our mortal flesh.","ref":"2 Corinthians 4:11","synthesized":"For we which live are alway delivered unto death for Jesus’ sake, that the life also of Jesus might be made manifest in our mortal flesh.","sources":{"KJV":{"text":"For we which live are alway delivered unto death for Jesus’ sake, that the life also of Jesus might be made manifest in our mortal flesh."}},"definableWords":["live","death","life","made","flesh"],"peopleInVerse":["Jesus"]},"12":{"text":"So then death worketh in us, but life in you.","ref":"2 Corinthians 4:12","synthesized":"So then death worketh in us, but life in you.","sources":{"KJV":{"text":"So then death worketh in us, but life in you."}},"definableWords":["death","life"],"peopleInVerse":[]},"13":{"text":"We having the same spirit of faith, according as it is written, I believed, and therefore have I spoken; we also believe, and therefore speak;","ref":"2 Corinthians 4:13","synthesized":"We having the same spirit of faith, according as it is written, I believed, and therefore have I spoken; we also believe, and therefore speak;","sources":{"KJV":{"text":"We having the same spirit of faith, according as it is written, I believed, and therefore have I spoken; we also believe, and therefore speak;"}},"definableWords":["spirit","faith","believed"],"peopleInVerse":[]},"14":{"text":"Knowing that he which raised up the Lord Jesus shall raise up us also by Jesus, and shall present us with you.","ref":"2 Corinthians 4:14","synthesized":"Knowing that he which raised up the Lord Jesus shall raise up us also by Jesus, and shall present us with you.","sources":{"KJV":{"text":"Knowing that he which raised up the Lord Jesus shall raise up us also by Jesus, and shall present us with you."}},"definableWords":["Lord"],"peopleInVerse":["Jesus"]},"15":{"text":"For all things are for your sakes, that the abundant grace might through the thanksgiving of many redound to the glory of God.","ref":"2 Corinthians 4:15","synthesized":"For all things are for your sakes, that the abundant grace might through the thanksgiving of many redound to the glory of God.","sources":{"KJV":{"text":"For all things are for your sakes, that the abundant grace might through the thanksgiving of many redound to the glory of God."}},"definableWords":["God"],"peopleInVerse":[]},"16":{"text":"For which cause we faint not; but though our outward man perish, yet the inward man is renewed day by day.","ref":"2 Corinthians 4:16","synthesized":"For which cause we faint not; but though our outward man perish, yet the inward man is renewed day by day.","sources":{"KJV":{"text":"For which cause we faint not; but though our outward man perish, yet the inward man is renewed day by day."}},"definableWords":["man","day"],"peopleInVerse":[]},"17":{"text":"For our light affliction, which is but for a moment, worketh for us a far more exceeding and eternal weight of glory;","ref":"2 Corinthians 4:17","synthesized":"For our light affliction, which is but for a moment, worketh for us a far more exceeding and eternal weight of glory;","sources":{"KJV":{"text":"For our light affliction, which is but for a moment, worketh for us a far more exceeding and eternal weight of glory;"}},"definableWords":["light"],"peopleInVerse":[]},"18":{"text":"While we look not at the things which are seen, but at the things which are not seen: for the things which are seen are temporal; but the things which are not seen are eternal.","ref":"2 Corinthians 4:18","synthesized":"While we look not at the things which are seen, but at the things which are not seen: for the things which are seen are temporal; but the things which are not seen are eternal.","sources":{"KJV":{"text":"While we look not at the things which are seen, but at the things which are not seen: for the things which are seen are temporal; but the things which are not seen are eternal."}},"definableWords":[],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"WE ARE AMBASSADORS FOR CHRIST","verses":{"1":{"text":"For we know that if our earthly house of this tabernacle were dissolved, we have a building of God, an house not made with hands, eternal in the heavens.","ref":"2 Corinthians 5:1","synthesized":"For we know that if our earthly house of this tabernacle were dissolved, we have a building of God, an house not made with hands, eternal in the heavens.","sources":{"KJV":{"text":"For we know that if our earthly house of this tabernacle were dissolved, we have a building of God, an house not made with hands, eternal in the heavens."}},"definableWords":["house","God","made","heavens"],"peopleInVerse":[]},"2":{"text":"For in this we groan, earnestly desiring to be clothed upon with our house which is from heaven:","ref":"2 Corinthians 5:2","synthesized":"For in this we groan, earnestly desiring to be clothed upon with our house which is from heaven:","sources":{"KJV":{"text":"For in this we groan, earnestly desiring to be clothed upon with our house which is from heaven:"}},"definableWords":["house","heaven"],"peopleInVerse":[]},"3":{"text":"If so be that being clothed we shall not be found naked.","ref":"2 Corinthians 5:3","synthesized":"If so be that being clothed we shall not be found naked.","sources":{"KJV":{"text":"If so be that being clothed we shall not be found naked."}},"definableWords":["naked"],"peopleInVerse":[]},"4":{"text":"For we that are in this tabernacle do groan, being burdened: not for that we would be unclothed, but clothed upon, that mortality might be swallowed up of life.","ref":"2 Corinthians 5:4","synthesized":"For we that are in this tabernacle do groan, being burdened: not for that we would be unclothed, but clothed upon, that mortality might be swallowed up of life.","sources":{"KJV":{"text":"For we that are in this tabernacle do groan, being burdened: not for that we would be unclothed, but clothed upon, that mortality might be swallowed up of life."}},"definableWords":["life"],"peopleInVerse":[]},"5":{"text":"Now he that hath wrought us for the selfsame thing is God, who also hath given unto us the earnest of the Spirit.","ref":"2 Corinthians 5:5","synthesized":"Now he that hath wrought us for the selfsame thing is God, who also hath given unto us the earnest of the Spirit.","sources":{"KJV":{"text":"Now he that hath wrought us for the selfsame thing is God, who also hath given unto us the earnest of the Spirit."}},"definableWords":["God","Spirit"],"peopleInVerse":[]},"6":{"text":"Therefore we are always confident, knowing that, whilst we are at home in the body, we are absent from the Lord:","ref":"2 Corinthians 5:6","synthesized":"Therefore we are always confident, knowing that, whilst we are at home in the body, we are absent from the Lord:","sources":{"KJV":{"text":"Therefore we are always confident, knowing that, whilst we are at home in the body, we are absent from the Lord:"}},"definableWords":["Lord"],"peopleInVerse":[]},"7":{"text":"(For we walk by faith, not by sight:)","ref":"2 Corinthians 5:7","synthesized":"(For we walk by faith, not by sight:)","sources":{"KJV":{"text":"(For we walk by faith, not by sight:)"}},"definableWords":["walk","faith"],"peopleInVerse":[]},"8":{"text":"We are confident, I say, and willing rather to be absent from the body, and to be present with the Lord.","ref":"2 Corinthians 5:8","synthesized":"We are confident, I say, and willing rather to be absent from the body, and to be present with the Lord.","sources":{"KJV":{"text":"We are confident, I say, and willing rather to be absent from the body, and to be present with the Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"9":{"text":"Wherefore we labour, that, whether present or absent, we may be accepted of him.","ref":"2 Corinthians 5:9","synthesized":"Wherefore we labour, that, whether present or absent, we may be accepted of him.","sources":{"KJV":{"text":"Wherefore we labour, that, whether present or absent, we may be accepted of him."}},"definableWords":["or"],"peopleInVerse":[]},"10":{"text":"For we must all appear before the judgment seat of Christ; that every one may receive the things done in his body, according to that he hath done, whether it be good or bad.","ref":"2 Corinthians 5:10","synthesized":"For we must all appear before the judgment seat of Christ; that every one may receive the things done in his body, according to that he hath done, whether it be good or bad.","sources":{"KJV":{"text":"For we must all appear before the judgment seat of Christ; that every one may receive the things done in his body, according to that he hath done, whether it be good or bad."}},"definableWords":["judgment","one","good","or"],"peopleInVerse":[]},"11":{"text":"Knowing therefore the terror of the Lord, we persuade men; but we are made manifest unto God; and I trust also are made manifest in your consciences.","ref":"2 Corinthians 5:11","synthesized":"Knowing therefore the terror of the Lord, we persuade men; but we are made manifest unto God; and I trust also are made manifest in your consciences.","sources":{"KJV":{"text":"Knowing therefore the terror of the Lord, we persuade men; but we are made manifest unto God; and I trust also are made manifest in your consciences."}},"definableWords":["Lord","men","made","God"],"peopleInVerse":[]},"12":{"text":"For we commend not ourselves again unto you, but give you occasion to glory on our behalf, that ye may have somewhat to answer them which glory in appearance, and not in heart.","ref":"2 Corinthians 5:12","synthesized":"For we commend not ourselves again unto you, but give you occasion to glory on our behalf, that ye may have somewhat to answer them which glory in appearance, and not in heart.","sources":{"KJV":{"text":"For we commend not ourselves again unto you, but give you occasion to glory on our behalf, that ye may have somewhat to answer them which glory in appearance, and not in heart."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"For whether we be beside ourselves, it is to God: or whether we be sober, it is for your cause.","ref":"2 Corinthians 5:13","synthesized":"For whether we be beside ourselves, it is to God: or whether we be sober, it is for your cause.","sources":{"KJV":{"text":"For whether we be beside ourselves, it is to God: or whether we be sober, it is for your cause."}},"definableWords":["God","or"],"peopleInVerse":[]},"14":{"text":"For the love of Christ constraineth us; because we thus judge, that if one died for all, then were all dead:","ref":"2 Corinthians 5:14","synthesized":"For the love of Christ constraineth us; because we thus judge, that if one died for all, then were all dead:","sources":{"KJV":{"text":"For the love of Christ constraineth us; because we thus judge, that if one died for all, then were all dead:"}},"definableWords":["love","one"],"peopleInVerse":[]},"15":{"text":"And that he died for all, that they which live should not henceforth live unto themselves, but unto him which died for them, and rose again.","ref":"2 Corinthians 5:15","synthesized":"And that he died for all, that they which live should not henceforth live unto themselves, but unto him which died for them, and rose again.","sources":{"KJV":{"text":"And that he died for all, that they which live should not henceforth live unto themselves, but unto him which died for them, and rose again."}},"definableWords":["live"],"peopleInVerse":[]},"16":{"text":"Wherefore henceforth know we no man after the flesh: yea, though we have known Christ after the flesh, yet now henceforth know we him no more.","ref":"2 Corinthians 5:16","synthesized":"Wherefore henceforth know we no man after the flesh: yea, though we have known Christ after the flesh, yet now henceforth know we him no more.","sources":{"KJV":{"text":"Wherefore henceforth know we no man after the flesh: yea, though we have known Christ after the flesh, yet now henceforth know we him no more."}},"definableWords":["man","flesh"],"peopleInVerse":[]},"17":{"text":"Therefore if any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new.","ref":"2 Corinthians 5:17","synthesized":"Therefore if any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new.","sources":{"KJV":{"text":"Therefore if any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new."}},"definableWords":["man"],"peopleInVerse":[]},"18":{"text":"And all things are of God, who hath reconciled us to himself by Jesus Christ, and hath given to us the ministry of reconciliation;","ref":"2 Corinthians 5:18","synthesized":"And all things are of God, who hath reconciled us to himself by Jesus Christ, and hath given to us the ministry of reconciliation;","sources":{"KJV":{"text":"And all things are of God, who hath reconciled us to himself by Jesus Christ, and hath given to us the ministry of reconciliation;"}},"definableWords":["God"],"peopleInVerse":["Jesus"]},"19":{"text":"To wit, that God was in Christ, reconciling the world unto himself, not imputing their trespasses unto them; and hath committed unto us the word of reconciliation.","ref":"2 Corinthians 5:19","synthesized":"To wit, that God was in Christ, reconciling the world unto himself, not imputing their trespasses unto them; and hath committed unto us the word of reconciliation.","sources":{"KJV":{"text":"To wit, that God was in Christ, reconciling the world unto himself, not imputing their trespasses unto them; and hath committed unto us the word of reconciliation."}},"definableWords":["God","word"],"peopleInVerse":[]},"20":{"text":"Now then we are ambassadors for Christ, as though God did beseech you by us: we pray you in Christ’s stead, be ye reconciled to God.","ref":"2 Corinthians 5:20","synthesized":"Now then we are ambassadors for Christ, as though God did beseech you by us: we pray you in Christ’s stead, be ye reconciled to God.","sources":{"KJV":{"text":"Now then we are ambassadors for Christ, as though God did beseech you by us: we pray you in Christ’s stead, be ye reconciled to God."}},"definableWords":["God"],"peopleInVerse":[]},"21":{"text":"For he hath made him to be sin for us, who knew no sin; that we might be made the righteousness of God in him.","ref":"2 Corinthians 5:21","synthesized":"For he hath made him to be sin for us, who knew no sin; that we might be made the righteousness of God in him.","sources":{"KJV":{"text":"For he hath made him to be sin for us, who knew no sin; that we might be made the righteousness of God in him."}},"definableWords":["made","sin","righteousness","God"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"BE NOT UNEQUALLY YOKED","verses":{"1":{"text":"We then, as workers together with him, beseech you also that ye receive not the grace of God in vain.","ref":"2 Corinthians 6:1","synthesized":"We then, as workers together with him, beseech you also that ye receive not the grace of God in vain.","sources":{"KJV":{"text":"We then, as workers together with him, beseech you also that ye receive not the grace of God in vain."}},"definableWords":["God"],"peopleInVerse":[]},"2":{"text":"(For he saith, I have heard thee in a time accepted, and in the day of salvation have I succoured thee: behold, now is the accepted time; behold, now is the day of salvation.)","ref":"2 Corinthians 6:2","synthesized":"(For he saith, I have heard thee in a time accepted, and in the day of salvation have I succoured thee: behold, now is the accepted time; behold, now is the day of salvation.)","sources":{"KJV":{"text":"(For he saith, I have heard thee in a time accepted, and in the day of salvation have I succoured thee: behold, now is the accepted time; behold, now is the day of salvation.)"}},"definableWords":["day"],"peopleInVerse":[]},"3":{"text":"Giving no offence in any thing, that the ministry be not blamed:","ref":"2 Corinthians 6:3","synthesized":"Giving no offence in any thing, that the ministry be not blamed:","sources":{"KJV":{"text":"Giving no offence in any thing, that the ministry be not blamed:"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"But in all things approving ourselves as the ministers of God, in much patience, in afflictions, in necessities, in distresses,","ref":"2 Corinthians 6:4","synthesized":"But in all things approving ourselves as the ministers of God, in much patience, in afflictions, in necessities, in distresses,","sources":{"KJV":{"text":"But in all things approving ourselves as the ministers of God, in much patience, in afflictions, in necessities, in distresses,"}},"definableWords":["God"],"peopleInVerse":[]},"5":{"text":"In stripes, in imprisonments, in tumults, in labours, in watchings, in fastings;","ref":"2 Corinthians 6:5","synthesized":"In stripes, in imprisonments, in tumults, in labours, in watchings, in fastings;","sources":{"KJV":{"text":"In stripes, in imprisonments, in tumults, in labours, in watchings, in fastings;"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"By pureness, by knowledge, by longsuffering, by kindness, by the Holy Ghost, by love unfeigned,","ref":"2 Corinthians 6:6","synthesized":"By pureness, by knowledge, by longsuffering, by kindness, by the Holy Ghost, by love unfeigned,","sources":{"KJV":{"text":"By pureness, by knowledge, by longsuffering, by kindness, by the Holy Ghost, by love unfeigned,"}},"definableWords":["knowledge","kindness","love"],"peopleInVerse":[]},"7":{"text":"By the word of truth, by the power of God, by the armour of righteousness on the right hand and on the left,","ref":"2 Corinthians 6:7","synthesized":"By the word of truth, by the power of God, by the armour of righteousness on the right hand and on the left,","sources":{"KJV":{"text":"By the word of truth, by the power of God, by the armour of righteousness on the right hand and on the left,"}},"definableWords":["word","God","righteousness"],"peopleInVerse":[]},"8":{"text":"By honour and dishonour, by evil report and good report: as deceivers, and yet true;","ref":"2 Corinthians 6:8","synthesized":"By honour and dishonour, by evil report and good report: as deceivers, and yet true;","sources":{"KJV":{"text":"By honour and dishonour, by evil report and good report: as deceivers, and yet true;"}},"definableWords":["evil","good"],"peopleInVerse":[]},"9":{"text":"As unknown, and yet well known; as dying, and, behold, we live; as chastened, and not killed;","ref":"2 Corinthians 6:9","synthesized":"As unknown, and yet well known; as dying, and, behold, we live; as chastened, and not killed;","sources":{"KJV":{"text":"As unknown, and yet well known; as dying, and, behold, we live; as chastened, and not killed;"}},"definableWords":["live"],"peopleInVerse":[]},"10":{"text":"As sorrowful, yet alway rejoicing; as poor, yet making many rich; as having nothing, and yet possessing all things.","ref":"2 Corinthians 6:10","synthesized":"As sorrowful, yet alway rejoicing; as poor, yet making many rich; as having nothing, and yet possessing all things.","sources":{"KJV":{"text":"As sorrowful, yet alway rejoicing; as poor, yet making many rich; as having nothing, and yet possessing all things."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"O ye Corinthians, our mouth is open unto you, our heart is enlarged.","ref":"2 Corinthians 6:11","synthesized":"O ye Corinthians, our mouth is open unto you, our heart is enlarged.","sources":{"KJV":{"text":"O ye Corinthians, our mouth is open unto you, our heart is enlarged."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Ye are not straitened in us, but ye are straitened in your own bowels.","ref":"2 Corinthians 6:12","synthesized":"Ye are not straitened in us, but ye are straitened in your own bowels.","sources":{"KJV":{"text":"Ye are not straitened in us, but ye are straitened in your own bowels."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Now for a recompence in the same, (I speak as unto my children,) be ye also enlarged.","ref":"2 Corinthians 6:13","synthesized":"Now for a recompence in the same, (I speak as unto my children,) be ye also enlarged.","sources":{"KJV":{"text":"Now for a recompence in the same, (I speak as unto my children,) be ye also enlarged."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Be ye not unequally yoked together with unbelievers: for what fellowship hath righteousness with unrighteousness? and what communion hath light with darkness?","ref":"2 Corinthians 6:14","synthesized":"Be ye not unequally yoked together with unbelievers: for what fellowship hath righteousness with unrighteousness? and what communion hath light with darkness?","sources":{"KJV":{"text":"Be ye not unequally yoked together with unbelievers: for what fellowship hath righteousness with unrighteousness? and what communion hath light with darkness?"}},"definableWords":["righteousness","light","darkness"],"peopleInVerse":[]},"15":{"text":"And what concord hath Christ with Belial? or what part hath he that believeth with an infidel?","ref":"2 Corinthians 6:15","synthesized":"And what concord hath Christ with Belial? or what part hath he that believeth with an infidel?","sources":{"KJV":{"text":"And what concord hath Christ with Belial? or what part hath he that believeth with an infidel?"}},"definableWords":["or"],"peopleInVerse":[]},"16":{"text":"And what agreement hath the temple of God with idols? for ye are the temple of the living God; as God hath said, I will dwell in them, and walk in them; and I will be their God, and they shall be my people.","ref":"2 Corinthians 6:16","synthesized":"And what agreement hath the temple of God with idols? for ye are the temple of the living God; as God hath said, I will dwell in them, and walk in them; and I will be their God, and they shall be my people.","sources":{"KJV":{"text":"And what agreement hath the temple of God with idols? for ye are the temple of the living God; as God hath said, I will dwell in them, and walk in them; and I will be their God, and they shall be my people."}},"definableWords":["God","living","walk","people"],"peopleInVerse":[]},"17":{"text":"Wherefore come out from among them, and be ye separate, saith the Lord, and touch not the unclean thing; and I will receive you,","ref":"2 Corinthians 6:17","synthesized":"Wherefore come out from among them, and be ye separate, saith the Lord, and touch not the unclean thing; and I will receive you,","sources":{"KJV":{"text":"Wherefore come out from among them, and be ye separate, saith the Lord, and touch not the unclean thing; and I will receive you,"}},"definableWords":["Lord"],"peopleInVerse":[]},"18":{"text":"And will be a Father unto you, and ye shall be my sons and daughters, saith the Lord Almighty.","ref":"2 Corinthians 6:18","synthesized":"And will be a Father unto you, and ye shall be my sons and daughters, saith the Lord Almighty.","sources":{"KJV":{"text":"And will be a Father unto you, and ye shall be my sons and daughters, saith the Lord Almighty."}},"definableWords":["father","sons","daughters","Lord"],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"GODLY SORROW WORKETH REPENTANCE","verses":{"1":{"text":"Having therefore these promises, dearly beloved, let us cleanse ourselves from all filthiness of the flesh and spirit, perfecting holiness in the fear of God.","ref":"2 Corinthians 7:1","synthesized":"Having therefore these promises, dearly beloved, let us cleanse ourselves from all filthiness of the flesh and spirit, perfecting holiness in the fear of God.","sources":{"KJV":{"text":"Having therefore these promises, dearly beloved, let us cleanse ourselves from all filthiness of the flesh and spirit, perfecting holiness in the fear of God."}},"definableWords":["flesh","spirit","fear","God"],"peopleInVerse":[]},"2":{"text":"Receive us; we have wronged no man, we have corrupted no man, we have defrauded no man.","ref":"2 Corinthians 7:2","synthesized":"Receive us; we have wronged no man, we have corrupted no man, we have defrauded no man.","sources":{"KJV":{"text":"Receive us; we have wronged no man, we have corrupted no man, we have defrauded no man."}},"definableWords":["man"],"peopleInVerse":[]},"3":{"text":"I speak not this to condemn you: for I have said before, that ye are in our hearts to die and live with you.","ref":"2 Corinthians 7:3","synthesized":"I speak not this to condemn you: for I have said before, that ye are in our hearts to die and live with you.","sources":{"KJV":{"text":"I speak not this to condemn you: for I have said before, that ye are in our hearts to die and live with you."}},"definableWords":["die","live"],"peopleInVerse":[]},"4":{"text":"Great is my boldness of speech toward you, great is my glorying of you: I am filled with comfort, I am exceeding joyful in all our tribulation.","ref":"2 Corinthians 7:4","synthesized":"Great is my boldness of speech toward you, great is my glorying of you: I am filled with comfort, I am exceeding joyful in all our tribulation.","sources":{"KJV":{"text":"Great is my boldness of speech toward you, great is my glorying of you: I am filled with comfort, I am exceeding joyful in all our tribulation."}},"definableWords":["great"],"peopleInVerse":[]},"5":{"text":"For, when we were come into Macedonia, our flesh had no rest, but we were troubled on every side; without were fightings, within were fears.","ref":"2 Corinthians 7:5","synthesized":"For, when we were come into Macedonia, our flesh had no rest, but we were troubled on every side; without were fightings, within were fears.","sources":{"KJV":{"text":"For, when we were come into Macedonia, our flesh had no rest, but we were troubled on every side; without were fightings, within were fears."}},"definableWords":["flesh","rest"],"peopleInVerse":[]},"6":{"text":"Nevertheless God, that comforteth those that are cast down, comforted us by the coming of Titus;","ref":"2 Corinthians 7:6","synthesized":"Nevertheless God, that comforteth those that are cast down, comforted us by the coming of Titus;","sources":{"KJV":{"text":"Nevertheless God, that comforteth those that are cast down, comforted us by the coming of Titus;"}},"definableWords":["God"],"peopleInVerse":[]},"7":{"text":"And not by his coming only, but by the consolation wherewith he was comforted in you, when he told us your earnest desire, your mourning, your fervent mind toward me; so that I rejoiced the more.","ref":"2 Corinthians 7:7","synthesized":"And not by his coming only, but by the consolation wherewith he was comforted in you, when he told us your earnest desire, your mourning, your fervent mind toward me; so that I rejoiced the more.","sources":{"KJV":{"text":"And not by his coming only, but by the consolation wherewith he was comforted in you, when he told us your earnest desire, your mourning, your fervent mind toward me; so that I rejoiced the more."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For though I made you sorry with a letter, I do not repent, though I did repent: for I perceive that the same epistle hath made you sorry, though it were but for a season.","ref":"2 Corinthians 7:8","synthesized":"For though I made you sorry with a letter, I do not repent, though I did repent: for I perceive that the same epistle hath made you sorry, though it were but for a season.","sources":{"KJV":{"text":"For though I made you sorry with a letter, I do not repent, though I did repent: for I perceive that the same epistle hath made you sorry, though it were but for a season."}},"definableWords":["made"],"peopleInVerse":[]},"9":{"text":"Now I rejoice, not that ye were made sorry, but that ye sorrowed to repentance: for ye were made sorry after a godly manner, that ye might receive damage by us in nothing.","ref":"2 Corinthians 7:9","synthesized":"Now I rejoice, not that ye were made sorry, but that ye sorrowed to repentance: for ye were made sorry after a godly manner, that ye might receive damage by us in nothing.","sources":{"KJV":{"text":"Now I rejoice, not that ye were made sorry, but that ye sorrowed to repentance: for ye were made sorry after a godly manner, that ye might receive damage by us in nothing."}},"definableWords":["made"],"peopleInVerse":[]},"10":{"text":"For godly sorrow worketh repentance to salvation not to be repented of: but the sorrow of the world worketh death.","ref":"2 Corinthians 7:10","synthesized":"For godly sorrow worketh repentance to salvation not to be repented of: but the sorrow of the world worketh death.","sources":{"KJV":{"text":"For godly sorrow worketh repentance to salvation not to be repented of: but the sorrow of the world worketh death."}},"definableWords":["death"],"peopleInVerse":[]},"11":{"text":"For behold this selfsame thing, that ye sorrowed after a godly sort, what carefulness it wrought in you, yea, what clearing of yourselves, yea, what indignation, yea, what fear, yea, what vehement desire, yea, what zeal, yea, what revenge! In all things ye have approved yourselves to be clear in this matter.","ref":"2 Corinthians 7:11","synthesized":"For behold this selfsame thing, that ye sorrowed after a godly sort, what carefulness it wrought in you, yea, what clearing of yourselves, yea, what indignation, yea, what fear, yea, what vehement desire, yea, what zeal, yea, what revenge! In all things ye have approved yourselves to be clear in this matter.","sources":{"KJV":{"text":"For behold this selfsame thing, that ye sorrowed after a godly sort, what carefulness it wrought in you, yea, what clearing of yourselves, yea, what indignation, yea, what fear, yea, what vehement desire, yea, what zeal, yea, what revenge! In all things ye have approved yourselves to be clear in this matter."}},"definableWords":["fear"],"peopleInVerse":[]},"12":{"text":"Wherefore, though I wrote unto you, I did it not for his cause that had done the wrong, nor for his cause that suffered wrong, but that our care for you in the sight of God might appear unto you.","ref":"2 Corinthians 7:12","synthesized":"Wherefore, though I wrote unto you, I did it not for his cause that had done the wrong, nor for his cause that suffered wrong, but that our care for you in the sight of God might appear unto you.","sources":{"KJV":{"text":"Wherefore, though I wrote unto you, I did it not for his cause that had done the wrong, nor for his cause that suffered wrong, but that our care for you in the sight of God might appear unto you."}},"definableWords":["God"],"peopleInVerse":[]},"13":{"text":"Therefore we were comforted in your comfort: yea, and exceedingly the more joyed we for the joy of Titus, because his spirit was refreshed by you all.","ref":"2 Corinthians 7:13","synthesized":"Therefore we were comforted in your comfort: yea, and exceedingly the more joyed we for the joy of Titus, because his spirit was refreshed by you all.","sources":{"KJV":{"text":"Therefore we were comforted in your comfort: yea, and exceedingly the more joyed we for the joy of Titus, because his spirit was refreshed by you all."}},"definableWords":["spirit"],"peopleInVerse":[]},"14":{"text":"For if I have boasted any thing to him of you, I am not ashamed; but as we spake all things to you in truth, even so our boasting, which I made before Titus, is found a truth.","ref":"2 Corinthians 7:14","synthesized":"For if I have boasted any thing to him of you, I am not ashamed; but as we spake all things to you in truth, even so our boasting, which I made before Titus, is found a truth.","sources":{"KJV":{"text":"For if I have boasted any thing to him of you, I am not ashamed; but as we spake all things to you in truth, even so our boasting, which I made before Titus, is found a truth."}},"definableWords":["made"],"peopleInVerse":[]},"15":{"text":"And his inward affection is more abundant toward you, whilst he remembereth the obedience of you all, how with fear and trembling ye received him.","ref":"2 Corinthians 7:15","synthesized":"And his inward affection is more abundant toward you, whilst he remembereth the obedience of you all, how with fear and trembling ye received him.","sources":{"KJV":{"text":"And his inward affection is more abundant toward you, whilst he remembereth the obedience of you all, how with fear and trembling ye received him."}},"definableWords":["fear"],"peopleInVerse":[]},"16":{"text":"I rejoice therefore that I have confidence in you in all things.","ref":"2 Corinthians 7:16","synthesized":"I rejoice therefore that I have confidence in you in all things.","sources":{"KJV":{"text":"I rejoice therefore that I have confidence in you in all things."}},"definableWords":[],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"THE GRACE OF GIVING — MACEDONIA'S EXAMPLE","verses":{"1":{"text":"Moreover, brethren, we do you to wit of the grace of God bestowed on the churches of Macedonia;","ref":"2 Corinthians 8:1","synthesized":"Moreover, brethren, we do you to wit of the grace of God bestowed on the churches of Macedonia;","sources":{"KJV":{"text":"Moreover, brethren, we do you to wit of the grace of God bestowed on the churches of Macedonia;"}},"definableWords":["brethren","God"],"peopleInVerse":[]},"2":{"text":"How that in a great trial of affliction the abundance of their joy and their deep poverty abounded unto the riches of their liberality.","ref":"2 Corinthians 8:2","synthesized":"How that in a great trial of affliction the abundance of their joy and their deep poverty abounded unto the riches of their liberality.","sources":{"KJV":{"text":"How that in a great trial of affliction the abundance of their joy and their deep poverty abounded unto the riches of their liberality."}},"definableWords":["great","deep"],"peopleInVerse":[]},"3":{"text":"For to their power, I bear record, yea, and beyond their power they were willing of themselves;","ref":"2 Corinthians 8:3","synthesized":"For to their power, I bear record, yea, and beyond their power they were willing of themselves;","sources":{"KJV":{"text":"For to their power, I bear record, yea, and beyond their power they were willing of themselves;"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Praying us with much intreaty that we would receive the gift, and take upon us the fellowship of the ministering to the saints.","ref":"2 Corinthians 8:4","synthesized":"Praying us with much intreaty that we would receive the gift, and take upon us the fellowship of the ministering to the saints.","sources":{"KJV":{"text":"Praying us with much intreaty that we would receive the gift, and take upon us the fellowship of the ministering to the saints."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"And this they did, not as we hoped, but first gave their own selves to the Lord, and unto us by the will of God.","ref":"2 Corinthians 8:5","synthesized":"And this they did, not as we hoped, but first gave their own selves to the Lord, and unto us by the will of God.","sources":{"KJV":{"text":"And this they did, not as we hoped, but first gave their own selves to the Lord, and unto us by the will of God."}},"definableWords":["Lord","God"],"peopleInVerse":[]},"6":{"text":"Insomuch that we desired Titus, that as he had begun, so he would also finish in you the same grace also.","ref":"2 Corinthians 8:6","synthesized":"Insomuch that we desired Titus, that as he had begun, so he would also finish in you the same grace also.","sources":{"KJV":{"text":"Insomuch that we desired Titus, that as he had begun, so he would also finish in you the same grace also."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Therefore, as ye abound in every thing, in faith, and utterance, and knowledge, and in all diligence, and in your love to us, see that ye abound in this grace also.","ref":"2 Corinthians 8:7","synthesized":"Therefore, as ye abound in every thing, in faith, and utterance, and knowledge, and in all diligence, and in your love to us, see that ye abound in this grace also.","sources":{"KJV":{"text":"Therefore, as ye abound in every thing, in faith, and utterance, and knowledge, and in all diligence, and in your love to us, see that ye abound in this grace also."}},"definableWords":["faith","knowledge","love","see"],"peopleInVerse":[]},"8":{"text":"I speak not by commandment, but by occasion of the forwardness of others, and to prove the sincerity of your love.","ref":"2 Corinthians 8:8","synthesized":"I speak not by commandment, but by occasion of the forwardness of others, and to prove the sincerity of your love.","sources":{"KJV":{"text":"I speak not by commandment, but by occasion of the forwardness of others, and to prove the sincerity of your love."}},"definableWords":["love"],"peopleInVerse":[]},"9":{"text":"For ye know the grace of our Lord Jesus Christ, that, though he was rich, yet for your sakes he became poor, that ye through his poverty might be rich.","ref":"2 Corinthians 8:9","synthesized":"For ye know the grace of our Lord Jesus Christ, that, though he was rich, yet for your sakes he became poor, that ye through his poverty might be rich.","sources":{"KJV":{"text":"For ye know the grace of our Lord Jesus Christ, that, though he was rich, yet for your sakes he became poor, that ye through his poverty might be rich."}},"definableWords":["Lord"],"peopleInVerse":["Jesus"]},"10":{"text":"And herein I give my advice: for this is expedient for you, who have begun before, not only to do, but also to be forward a year ago.","ref":"2 Corinthians 8:10","synthesized":"And herein I give my advice: for this is expedient for you, who have begun before, not only to do, but also to be forward a year ago.","sources":{"KJV":{"text":"And herein I give my advice: for this is expedient for you, who have begun before, not only to do, but also to be forward a year ago."}},"definableWords":["year"],"peopleInVerse":[]},"11":{"text":"Now therefore perform the doing of it; that as there was a readiness to will, so there may be a performance also out of that which ye have.","ref":"2 Corinthians 8:11","synthesized":"Now therefore perform the doing of it; that as there was a readiness to will, so there may be a performance also out of that which ye have.","sources":{"KJV":{"text":"Now therefore perform the doing of it; that as there was a readiness to will, so there may be a performance also out of that which ye have."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For if there be first a willing mind, it is accepted according to that a man hath, and not according to that he hath not.","ref":"2 Corinthians 8:12","synthesized":"For if there be first a willing mind, it is accepted according to that a man hath, and not according to that he hath not.","sources":{"KJV":{"text":"For if there be first a willing mind, it is accepted according to that a man hath, and not according to that he hath not."}},"definableWords":["man"],"peopleInVerse":[]},"13":{"text":"For I mean not that other men be eased, and ye burdened:","ref":"2 Corinthians 8:13","synthesized":"For I mean not that other men be eased, and ye burdened:","sources":{"KJV":{"text":"For I mean not that other men be eased, and ye burdened:"}},"definableWords":["men"],"peopleInVerse":[]},"14":{"text":"But by an equality, that now at this time your abundance may be a supply for their want, that their abundance also may be a supply for your want: that there may be equality:","ref":"2 Corinthians 8:14","synthesized":"But by an equality, that now at this time your abundance may be a supply for their want, that their abundance also may be a supply for your want: that there may be equality:","sources":{"KJV":{"text":"But by an equality, that now at this time your abundance may be a supply for their want, that their abundance also may be a supply for your want: that there may be equality:"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"As it is written, He that had gathered much had nothing over; and he that had gathered little had no lack.","ref":"2 Corinthians 8:15","synthesized":"As it is written, He that had gathered much had nothing over; and he that had gathered little had no lack.","sources":{"KJV":{"text":"As it is written, He that had gathered much had nothing over; and he that had gathered little had no lack."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"But thanks be to God, which put the same earnest care into the heart of Titus for you.","ref":"2 Corinthians 8:16","synthesized":"But thanks be to God, which put the same earnest care into the heart of Titus for you.","sources":{"KJV":{"text":"But thanks be to God, which put the same earnest care into the heart of Titus for you."}},"definableWords":["God"],"peopleInVerse":[]},"17":{"text":"For indeed he accepted the exhortation; but being more forward, of his own accord he went unto you.","ref":"2 Corinthians 8:17","synthesized":"For indeed he accepted the exhortation; but being more forward, of his own accord he went unto you.","sources":{"KJV":{"text":"For indeed he accepted the exhortation; but being more forward, of his own accord he went unto you."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"And we have sent with him the brother, whose praise is in the gospel throughout all the churches;","ref":"2 Corinthians 8:18","synthesized":"And we have sent with him the brother, whose praise is in the gospel throughout all the churches;","sources":{"KJV":{"text":"And we have sent with him the brother, whose praise is in the gospel throughout all the churches;"}},"definableWords":["brother"],"peopleInVerse":[]},"19":{"text":"And not that only, but who was also chosen of the churches to travel with us with this grace, which is administered by us to the glory of the same Lord, and declaration of your ready mind:","ref":"2 Corinthians 8:19","synthesized":"And not that only, but who was also chosen of the churches to travel with us with this grace, which is administered by us to the glory of the same Lord, and declaration of your ready mind:","sources":{"KJV":{"text":"And not that only, but who was also chosen of the churches to travel with us with this grace, which is administered by us to the glory of the same Lord, and declaration of your ready mind:"}},"definableWords":["Lord"],"peopleInVerse":[]},"20":{"text":"Avoiding this, that no man should blame us in this abundance which is administered by us:","ref":"2 Corinthians 8:20","synthesized":"Avoiding this, that no man should blame us in this abundance which is administered by us:","sources":{"KJV":{"text":"Avoiding this, that no man should blame us in this abundance which is administered by us:"}},"definableWords":["man"],"peopleInVerse":[]},"21":{"text":"Providing for honest things, not only in the sight of the Lord, but also in the sight of men.","ref":"2 Corinthians 8:21","synthesized":"Providing for honest things, not only in the sight of the Lord, but also in the sight of men.","sources":{"KJV":{"text":"Providing for honest things, not only in the sight of the Lord, but also in the sight of men."}},"definableWords":["Lord","men"],"peopleInVerse":[]},"22":{"text":"And we have sent with them our brother, whom we have oftentimes proved diligent in many things, but now much more diligent, upon the great confidence which I have in you.","ref":"2 Corinthians 8:22","synthesized":"And we have sent with them our brother, whom we have oftentimes proved diligent in many things, but now much more diligent, upon the great confidence which I have in you.","sources":{"KJV":{"text":"And we have sent with them our brother, whom we have oftentimes proved diligent in many things, but now much more diligent, upon the great confidence which I have in you."}},"definableWords":["brother","great"],"peopleInVerse":[]},"23":{"text":"Whether any do enquire of Titus, he is my partner and fellowhelper concerning you: or our brethren be enquired of, they are the messengers of the churches, and the glory of Christ.","ref":"2 Corinthians 8:23","synthesized":"Whether any do enquire of Titus, he is my partner and fellowhelper concerning you: or our brethren be enquired of, they are the messengers of the churches, and the glory of Christ.","sources":{"KJV":{"text":"Whether any do enquire of Titus, he is my partner and fellowhelper concerning you: or our brethren be enquired of, they are the messengers of the churches, and the glory of Christ."}},"definableWords":["or","brethren"],"peopleInVerse":[]},"24":{"text":"Wherefore shew ye to them, and before the churches, the proof of your love, and of our boasting on your behalf.","ref":"2 Corinthians 8:24","synthesized":"Wherefore shew ye to them, and before the churches, the proof of your love, and of our boasting on your behalf.","sources":{"KJV":{"text":"Wherefore shew ye to them, and before the churches, the proof of your love, and of our boasting on your behalf."}},"definableWords":["love"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"GOD LOVES A CHEERFUL GIVER","verses":{"1":{"text":"For as touching the ministering to the saints, it is superfluous for me to write to you:","ref":"2 Corinthians 9:1","synthesized":"For as touching the ministering to the saints, it is superfluous for me to write to you:","sources":{"KJV":{"text":"For as touching the ministering to the saints, it is superfluous for me to write to you:"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"For I know the forwardness of your mind, for which I boast of you to them of Macedonia, that Achaia was ready a year ago; and your zeal hath provoked very many.","ref":"2 Corinthians 9:2","synthesized":"For I know the forwardness of your mind, for which I boast of you to them of Macedonia, that Achaia was ready a year ago; and your zeal hath provoked very many.","sources":{"KJV":{"text":"For I know the forwardness of your mind, for which I boast of you to them of Macedonia, that Achaia was ready a year ago; and your zeal hath provoked very many."}},"definableWords":["year"],"peopleInVerse":[]},"3":{"text":"Yet have I sent the brethren, lest our boasting of you should be in vain in this behalf; that, as I said, ye may be ready:","ref":"2 Corinthians 9:3","synthesized":"Yet have I sent the brethren, lest our boasting of you should be in vain in this behalf; that, as I said, ye may be ready:","sources":{"KJV":{"text":"Yet have I sent the brethren, lest our boasting of you should be in vain in this behalf; that, as I said, ye may be ready:"}},"definableWords":["brethren"],"peopleInVerse":[]},"4":{"text":"Lest haply if they of Macedonia come with me, and find you unprepared, we (that we say not, ye) should be ashamed in this same confident boasting.","ref":"2 Corinthians 9:4","synthesized":"Lest haply if they of Macedonia come with me, and find you unprepared, we (that we say not, ye) should be ashamed in this same confident boasting.","sources":{"KJV":{"text":"Lest haply if they of Macedonia come with me, and find you unprepared, we (that we say not, ye) should be ashamed in this same confident boasting."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Therefore I thought it necessary to exhort the brethren, that they would go before unto you, and make up beforehand your bounty, whereof ye had notice before, that the same might be ready, as a matter of bounty, and not as of covetousness.","ref":"2 Corinthians 9:5","synthesized":"Therefore I thought it necessary to exhort the brethren, that they would go before unto you, and make up beforehand your bounty, whereof ye had notice before, that the same might be ready, as a matter of bounty, and not as of covetousness.","sources":{"KJV":{"text":"Therefore I thought it necessary to exhort the brethren, that they would go before unto you, and make up beforehand your bounty, whereof ye had notice before, that the same might be ready, as a matter of bounty, and not as of covetousness."}},"definableWords":["brethren","make"],"peopleInVerse":[]},"6":{"text":"But this I say, He which soweth sparingly shall reap also sparingly; and he which soweth bountifully shall reap also bountifully.","ref":"2 Corinthians 9:6","synthesized":"But this I say, He which soweth sparingly shall reap also sparingly; and he which soweth bountifully shall reap also bountifully.","sources":{"KJV":{"text":"But this I say, He which soweth sparingly shall reap also sparingly; and he which soweth bountifully shall reap also bountifully."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Every man according as he purposeth in his heart, so let him give; not grudgingly, or of necessity: for God loveth a cheerful giver.","ref":"2 Corinthians 9:7","synthesized":"Every man according as he purposeth in his heart, so let him give; not grudgingly, or of necessity: for God loveth a cheerful giver.","sources":{"KJV":{"text":"Every man according as he purposeth in his heart, so let him give; not grudgingly, or of necessity: for God loveth a cheerful giver."}},"definableWords":["man","or","God"],"peopleInVerse":[]},"8":{"text":"And God is able to make all grace abound toward you; that ye, always having all sufficiency in all things, may abound to every good work:","ref":"2 Corinthians 9:8","synthesized":"And God is able to make all grace abound toward you; that ye, always having all sufficiency in all things, may abound to every good work:","sources":{"KJV":{"text":"And God is able to make all grace abound toward you; that ye, always having all sufficiency in all things, may abound to every good work:"}},"definableWords":["God","make","good","work"],"peopleInVerse":[]},"9":{"text":"(As it is written, He hath dispersed abroad; he hath given to the poor: his righteousness remaineth for ever.","ref":"2 Corinthians 9:9","synthesized":"(As it is written, He hath dispersed abroad; he hath given to the poor: his righteousness remaineth for ever.","sources":{"KJV":{"text":"(As it is written, He hath dispersed abroad; he hath given to the poor: his righteousness remaineth for ever."}},"definableWords":["righteousness"],"peopleInVerse":[]},"10":{"text":"Now he that ministereth seed to the sower both minister bread for your food, and multiply your seed sown, and increase the fruits of your righteousness;)","ref":"2 Corinthians 9:10","synthesized":"Now he that ministereth seed to the sower both minister bread for your food, and multiply your seed sown, and increase the fruits of your righteousness;)","sources":{"KJV":{"text":"Now he that ministereth seed to the sower both minister bread for your food, and multiply your seed sown, and increase the fruits of your righteousness;)"}},"definableWords":["seed","multiply","righteousness"],"peopleInVerse":[]},"11":{"text":"Being enriched in every thing to all bountifulness, which causeth through us thanksgiving to God.","ref":"2 Corinthians 9:11","synthesized":"Being enriched in every thing to all bountifulness, which causeth through us thanksgiving to God.","sources":{"KJV":{"text":"Being enriched in every thing to all bountifulness, which causeth through us thanksgiving to God."}},"definableWords":["God"],"peopleInVerse":[]},"12":{"text":"For the administration of this service not only supplieth the want of the saints, but is abundant also by many thanksgivings unto God;","ref":"2 Corinthians 9:12","synthesized":"For the administration of this service not only supplieth the want of the saints, but is abundant also by many thanksgivings unto God;","sources":{"KJV":{"text":"For the administration of this service not only supplieth the want of the saints, but is abundant also by many thanksgivings unto God;"}},"definableWords":["God"],"peopleInVerse":[]},"13":{"text":"Whiles by the experiment of this ministration they glorify God for your professed subjection unto the gospel of Christ, and for your liberal distribution unto them, and unto all men;","ref":"2 Corinthians 9:13","synthesized":"Whiles by the experiment of this ministration they glorify God for your professed subjection unto the gospel of Christ, and for your liberal distribution unto them, and unto all men;","sources":{"KJV":{"text":"Whiles by the experiment of this ministration they glorify God for your professed subjection unto the gospel of Christ, and for your liberal distribution unto them, and unto all men;"}},"definableWords":["God","men"],"peopleInVerse":[]},"14":{"text":"And by their prayer for you, which long after you for the exceeding grace of God in you.","ref":"2 Corinthians 9:14","synthesized":"And by their prayer for you, which long after you for the exceeding grace of God in you.","sources":{"KJV":{"text":"And by their prayer for you, which long after you for the exceeding grace of God in you."}},"definableWords":["God"],"peopleInVerse":[]},"15":{"text":"Thanks be unto God for his unspeakable gift.","ref":"2 Corinthians 9:15","synthesized":"Thanks be unto God for his unspeakable gift.","sources":{"KJV":{"text":"Thanks be unto God for his unspeakable gift."}},"definableWords":["God"],"peopleInVerse":[]}}},"10":{"chapter":"10","title":"WEAPONS NOT CARNAL","verses":{"1":{"text":"Now I Paul myself beseech you by the meekness and gentleness of Christ, who in presence am base among you, but being absent am bold toward you:","ref":"2 Corinthians 10:1","synthesized":"Now I Paul myself beseech you by the meekness and gentleness of Christ, who in presence am base among you, but being absent am bold toward you:","sources":{"KJV":{"text":"Now I Paul myself beseech you by the meekness and gentleness of Christ, who in presence am base among you, but being absent am bold toward you:"}},"definableWords":[],"peopleInVerse":["Paul"]},"2":{"text":"But I beseech you, that I may not be bold when I am present with that confidence, wherewith I think to be bold against some, which think of us as if we walked according to the flesh.","ref":"2 Corinthians 10:2","synthesized":"But I beseech you, that I may not be bold when I am present with that confidence, wherewith I think to be bold against some, which think of us as if we walked according to the flesh.","sources":{"KJV":{"text":"But I beseech you, that I may not be bold when I am present with that confidence, wherewith I think to be bold against some, which think of us as if we walked according to the flesh."}},"definableWords":["walked","flesh"],"peopleInVerse":[]},"3":{"text":"For though we walk in the flesh, we do not war after the flesh:","ref":"2 Corinthians 10:3","synthesized":"For though we walk in the flesh, we do not war after the flesh:","sources":{"KJV":{"text":"For though we walk in the flesh, we do not war after the flesh:"}},"definableWords":["walk","flesh"],"peopleInVerse":[]},"4":{"text":"(For the weapons of our warfare are not carnal, but mighty through God to the pulling down of strong holds;)","ref":"2 Corinthians 10:4","synthesized":"(For the weapons of our warfare are not carnal, but mighty through God to the pulling down of strong holds;)","sources":{"KJV":{"text":"(For the weapons of our warfare are not carnal, but mighty through God to the pulling down of strong holds;)"}},"definableWords":["mighty","God","strong"],"peopleInVerse":[]},"5":{"text":"Casting down imaginations, and every high thing that exalteth itself against the knowledge of God, and bringing into captivity every thought to the obedience of Christ;","ref":"2 Corinthians 10:5","synthesized":"Casting down imaginations, and every high thing that exalteth itself against the knowledge of God, and bringing into captivity every thought to the obedience of Christ;","sources":{"KJV":{"text":"Casting down imaginations, and every high thing that exalteth itself against the knowledge of God, and bringing into captivity every thought to the obedience of Christ;"}},"definableWords":["knowledge","God"],"peopleInVerse":[]},"6":{"text":"And having in a readiness to revenge all disobedience, when your obedience is fulfilled.","ref":"2 Corinthians 10:6","synthesized":"And having in a readiness to revenge all disobedience, when your obedience is fulfilled.","sources":{"KJV":{"text":"And having in a readiness to revenge all disobedience, when your obedience is fulfilled."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Do ye look on things after the outward appearance? If any man trust to himself that he is Christ’s, let him of himself think this again, that, as he is Christ’s, even so are we Christ’s.","ref":"2 Corinthians 10:7","synthesized":"Do ye look on things after the outward appearance? If any man trust to himself that he is Christ’s, let him of himself think this again, that, as he is Christ’s, even so are we Christ’s.","sources":{"KJV":{"text":"Do ye look on things after the outward appearance? If any man trust to himself that he is Christ’s, let him of himself think this again, that, as he is Christ’s, even so are we Christ’s."}},"definableWords":["man"],"peopleInVerse":[]},"8":{"text":"For though I should boast somewhat more of our authority, which the Lord hath given us for edification, and not for your destruction, I should not be ashamed:","ref":"2 Corinthians 10:8","synthesized":"For though I should boast somewhat more of our authority, which the Lord hath given us for edification, and not for your destruction, I should not be ashamed:","sources":{"KJV":{"text":"For though I should boast somewhat more of our authority, which the Lord hath given us for edification, and not for your destruction, I should not be ashamed:"}},"definableWords":["Lord"],"peopleInVerse":[]},"9":{"text":"That I may not seem as if I would terrify you by letters.","ref":"2 Corinthians 10:9","synthesized":"That I may not seem as if I would terrify you by letters.","sources":{"KJV":{"text":"That I may not seem as if I would terrify you by letters."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For his letters, say they, are weighty and powerful; but his bodily presence is weak, and his speech contemptible.","ref":"2 Corinthians 10:10","synthesized":"For his letters, say they, are weighty and powerful; but his bodily presence is weak, and his speech contemptible.","sources":{"KJV":{"text":"For his letters, say they, are weighty and powerful; but his bodily presence is weak, and his speech contemptible."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Let such an one think this, that, such as we are in word by letters when we are absent, such will we be also in deed when we are present.","ref":"2 Corinthians 10:11","synthesized":"Let such an one think this, that, such as we are in word by letters when we are absent, such will we be also in deed when we are present.","sources":{"KJV":{"text":"Let such an one think this, that, such as we are in word by letters when we are absent, such will we be also in deed when we are present."}},"definableWords":["one","word"],"peopleInVerse":[]},"12":{"text":"For we dare not make ourselves of the number, or compare ourselves with some that commend themselves: but they measuring themselves by themselves, and comparing themselves among themselves, are not wise.","ref":"2 Corinthians 10:12","synthesized":"For we dare not make ourselves of the number, or compare ourselves with some that commend themselves: but they measuring themselves by themselves, and comparing themselves among themselves, are not wise.","sources":{"KJV":{"text":"For we dare not make ourselves of the number, or compare ourselves with some that commend themselves: but they measuring themselves by themselves, and comparing themselves among themselves, are not wise."}},"definableWords":["make","or"],"peopleInVerse":[]},"13":{"text":"But we will not boast of things without our measure, but according to the measure of the rule which God hath distributed to us, a measure to reach even unto you.","ref":"2 Corinthians 10:13","synthesized":"But we will not boast of things without our measure, but according to the measure of the rule which God hath distributed to us, a measure to reach even unto you.","sources":{"KJV":{"text":"But we will not boast of things without our measure, but according to the measure of the rule which God hath distributed to us, a measure to reach even unto you."}},"definableWords":["rule","God"],"peopleInVerse":[]},"14":{"text":"For we stretch not ourselves beyond our measure, as though we reached not unto you: for we are come as far as to you also in preaching the gospel of Christ:","ref":"2 Corinthians 10:14","synthesized":"For we stretch not ourselves beyond our measure, as though we reached not unto you: for we are come as far as to you also in preaching the gospel of Christ:","sources":{"KJV":{"text":"For we stretch not ourselves beyond our measure, as though we reached not unto you: for we are come as far as to you also in preaching the gospel of Christ:"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Not boasting of things without our measure, that is, of other men’s labours; but having hope, when your faith is increased, that we shall be enlarged by you according to our rule abundantly,","ref":"2 Corinthians 10:15","synthesized":"Not boasting of things without our measure, that is, of other men’s labours; but having hope, when your faith is increased, that we shall be enlarged by you according to our rule abundantly,","sources":{"KJV":{"text":"Not boasting of things without our measure, that is, of other men’s labours; but having hope, when your faith is increased, that we shall be enlarged by you according to our rule abundantly,"}},"definableWords":["men","faith","rule"],"peopleInVerse":[]},"16":{"text":"To preach the gospel in the regions beyond you, and not to boast in another man’s line of things made ready to our hand.","ref":"2 Corinthians 10:16","synthesized":"To preach the gospel in the regions beyond you, and not to boast in another man’s line of things made ready to our hand.","sources":{"KJV":{"text":"To preach the gospel in the regions beyond you, and not to boast in another man’s line of things made ready to our hand."}},"definableWords":["man","made"],"peopleInVerse":[]},"17":{"text":"But he that glorieth, let him glory in the Lord.","ref":"2 Corinthians 10:17","synthesized":"But he that glorieth, let him glory in the Lord.","sources":{"KJV":{"text":"But he that glorieth, let him glory in the Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"18":{"text":"For not he that commendeth himself is approved, but whom the Lord commendeth.","ref":"2 Corinthians 10:18","synthesized":"For not he that commendeth himself is approved, but whom the Lord commendeth.","sources":{"KJV":{"text":"For not he that commendeth himself is approved, but whom the Lord commendeth."}},"definableWords":["Lord"],"peopleInVerse":[]}}},"11":{"chapter":"11","title":"PAUL'S SUFFERINGS AS AN APOSTLE","verses":{"1":{"text":"Would to God ye could bear with me a little in my folly: and indeed bear with me.","ref":"2 Corinthians 11:1","synthesized":"Would to God ye could bear with me a little in my folly: and indeed bear with me.","sources":{"KJV":{"text":"Would to God ye could bear with me a little in my folly: and indeed bear with me."}},"definableWords":["God"],"peopleInVerse":[]},"2":{"text":"For I am jealous over you with godly jealousy: for I have espoused you to one husband, that I may present you as a chaste virgin to Christ.","ref":"2 Corinthians 11:2","synthesized":"For I am jealous over you with godly jealousy: for I have espoused you to one husband, that I may present you as a chaste virgin to Christ.","sources":{"KJV":{"text":"For I am jealous over you with godly jealousy: for I have espoused you to one husband, that I may present you as a chaste virgin to Christ."}},"definableWords":["one","husband"],"peopleInVerse":[]},"3":{"text":"But I fear, lest by any means, as the serpent beguiled Eve through his subtilty, so your minds should be corrupted from the simplicity that is in Christ.","ref":"2 Corinthians 11:3","synthesized":"But I fear, lest by any means, as the serpent beguiled Eve through his subtilty, so your minds should be corrupted from the simplicity that is in Christ.","sources":{"KJV":{"text":"But I fear, lest by any means, as the serpent beguiled Eve through his subtilty, so your minds should be corrupted from the simplicity that is in Christ."}},"definableWords":["fear","serpent","Eve"],"peopleInVerse":["Eve"]},"4":{"text":"For if he that cometh preacheth another Jesus, whom we have not preached, or if ye receive another spirit, which ye have not received, or another gospel, which ye have not accepted, ye might well bear with him.","ref":"2 Corinthians 11:4","synthesized":"For if he that cometh preacheth another Jesus, whom we have not preached, or if ye receive another spirit, which ye have not received, or another gospel, which ye have not accepted, ye might well bear with him.","sources":{"KJV":{"text":"For if he that cometh preacheth another Jesus, whom we have not preached, or if ye receive another spirit, which ye have not received, or another gospel, which ye have not accepted, ye might well bear with him."}},"definableWords":["or","spirit"],"peopleInVerse":["Jesus"]},"5":{"text":"For I suppose I was not a whit behind the very chiefest apostles.","ref":"2 Corinthians 11:5","synthesized":"For I suppose I was not a whit behind the very chiefest apostles.","sources":{"KJV":{"text":"For I suppose I was not a whit behind the very chiefest apostles."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"But though I be rude in speech, yet not in knowledge; but we have been throughly made manifest among you in all things.","ref":"2 Corinthians 11:6","synthesized":"But though I be rude in speech, yet not in knowledge; but we have been throughly made manifest among you in all things.","sources":{"KJV":{"text":"But though I be rude in speech, yet not in knowledge; but we have been throughly made manifest among you in all things."}},"definableWords":["knowledge","made"],"peopleInVerse":[]},"7":{"text":"Have I committed an offence in abasing myself that ye might be exalted, because I have preached to you the gospel of God freely?","ref":"2 Corinthians 11:7","synthesized":"Have I committed an offence in abasing myself that ye might be exalted, because I have preached to you the gospel of God freely?","sources":{"KJV":{"text":"Have I committed an offence in abasing myself that ye might be exalted, because I have preached to you the gospel of God freely?"}},"definableWords":["God"],"peopleInVerse":[]},"8":{"text":"I robbed other churches, taking wages of them, to do you service.","ref":"2 Corinthians 11:8","synthesized":"I robbed other churches, taking wages of them, to do you service.","sources":{"KJV":{"text":"I robbed other churches, taking wages of them, to do you service."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"And when I was present with you, and wanted, I was chargeable to no man: for that which was lacking to me the brethren which came from Macedonia supplied: and in all things I have kept myself from being burdensome unto you, and so will I keep myself.","ref":"2 Corinthians 11:9","synthesized":"And when I was present with you, and wanted, I was chargeable to no man: for that which was lacking to me the brethren which came from Macedonia supplied: and in all things I have kept myself from being burdensome unto you, and so will I keep myself.","sources":{"KJV":{"text":"And when I was present with you, and wanted, I was chargeable to no man: for that which was lacking to me the brethren which came from Macedonia supplied: and in all things I have kept myself from being burdensome unto you, and so will I keep myself."}},"definableWords":["man","brethren","keep"],"peopleInVerse":[]},"10":{"text":"As the truth of Christ is in me, no man shall stop me of this boasting in the regions of Achaia.","ref":"2 Corinthians 11:10","synthesized":"As the truth of Christ is in me, no man shall stop me of this boasting in the regions of Achaia.","sources":{"KJV":{"text":"As the truth of Christ is in me, no man shall stop me of this boasting in the regions of Achaia."}},"definableWords":["man"],"peopleInVerse":[]},"11":{"text":"Wherefore? because I love you not? God knoweth.","ref":"2 Corinthians 11:11","synthesized":"Wherefore? because I love you not? God knoweth.","sources":{"KJV":{"text":"Wherefore? because I love you not? God knoweth."}},"definableWords":["love","God"],"peopleInVerse":[]},"12":{"text":"But what I do, that I will do, that I may cut off occasion from them which desire occasion; that wherein they glory, they may be found even as we.","ref":"2 Corinthians 11:12","synthesized":"But what I do, that I will do, that I may cut off occasion from them which desire occasion; that wherein they glory, they may be found even as we.","sources":{"KJV":{"text":"But what I do, that I will do, that I may cut off occasion from them which desire occasion; that wherein they glory, they may be found even as we."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"For such are false apostles, deceitful workers, transforming themselves into the apostles of Christ.","ref":"2 Corinthians 11:13","synthesized":"For such are false apostles, deceitful workers, transforming themselves into the apostles of Christ.","sources":{"KJV":{"text":"For such are false apostles, deceitful workers, transforming themselves into the apostles of Christ."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"And no marvel; for Satan himself is transformed into an angel of light.","ref":"2 Corinthians 11:14","synthesized":"And no marvel; for Satan himself is transformed into an angel of light.","sources":{"KJV":{"text":"And no marvel; for Satan himself is transformed into an angel of light."}},"definableWords":["light"],"peopleInVerse":[]},"15":{"text":"Therefore it is no great thing if his ministers also be transformed as the ministers of righteousness; whose end shall be according to their works.","ref":"2 Corinthians 11:15","synthesized":"Therefore it is no great thing if his ministers also be transformed as the ministers of righteousness; whose end shall be according to their works.","sources":{"KJV":{"text":"Therefore it is no great thing if his ministers also be transformed as the ministers of righteousness; whose end shall be according to their works."}},"definableWords":["great","righteousness","works"],"peopleInVerse":[]},"16":{"text":"I say again, Let no man think me a fool; if otherwise, yet as a fool receive me, that I may boast myself a little.","ref":"2 Corinthians 11:16","synthesized":"I say again, Let no man think me a fool; if otherwise, yet as a fool receive me, that I may boast myself a little.","sources":{"KJV":{"text":"I say again, Let no man think me a fool; if otherwise, yet as a fool receive me, that I may boast myself a little."}},"definableWords":["man"],"peopleInVerse":[]},"17":{"text":"That which I speak, I speak it not after the Lord, but as it were foolishly, in this confidence of boasting.","ref":"2 Corinthians 11:17","synthesized":"That which I speak, I speak it not after the Lord, but as it were foolishly, in this confidence of boasting.","sources":{"KJV":{"text":"That which I speak, I speak it not after the Lord, but as it were foolishly, in this confidence of boasting."}},"definableWords":["Lord"],"peopleInVerse":[]},"18":{"text":"Seeing that many glory after the flesh, I will glory also.","ref":"2 Corinthians 11:18","synthesized":"Seeing that many glory after the flesh, I will glory also.","sources":{"KJV":{"text":"Seeing that many glory after the flesh, I will glory also."}},"definableWords":["flesh"],"peopleInVerse":[]},"19":{"text":"For ye suffer fools gladly, seeing ye yourselves are wise.","ref":"2 Corinthians 11:19","synthesized":"For ye suffer fools gladly, seeing ye yourselves are wise.","sources":{"KJV":{"text":"For ye suffer fools gladly, seeing ye yourselves are wise."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"For ye suffer, if a man bring you into bondage, if a man devour you, if a man take of you, if a man exalt himself, if a man smite you on the face.","ref":"2 Corinthians 11:20","synthesized":"For ye suffer, if a man bring you into bondage, if a man devour you, if a man take of you, if a man exalt himself, if a man smite you on the face.","sources":{"KJV":{"text":"For ye suffer, if a man bring you into bondage, if a man devour you, if a man take of you, if a man exalt himself, if a man smite you on the face."}},"definableWords":["man"],"peopleInVerse":[]},"21":{"text":"I speak as concerning reproach, as though we had been weak. Howbeit whereinsoever any is bold, (I speak foolishly,) I am bold also.","ref":"2 Corinthians 11:21","synthesized":"I speak as concerning reproach, as though we had been weak. Howbeit whereinsoever any is bold, (I speak foolishly,) I am bold also.","sources":{"KJV":{"text":"I speak as concerning reproach, as though we had been weak. Howbeit whereinsoever any is bold, (I speak foolishly,) I am bold also."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Are they Hebrews? so am I. Are they Israelites? so am I. Are they the seed of Abraham? so am I.","ref":"2 Corinthians 11:22","synthesized":"Are they Hebrews? so am I. Are they Israelites? so am I. Are they the seed of Abraham? so am I.","sources":{"KJV":{"text":"Are they Hebrews? so am I. Are they Israelites? so am I. Are they the seed of Abraham? so am I."}},"definableWords":["Israelites","seed","Abraham"],"peopleInVerse":["Abraham"]},"23":{"text":"Are they ministers of Christ? (I speak as a fool) I am more; in labours more abundant, in stripes above measure, in prisons more frequent, in deaths oft.","ref":"2 Corinthians 11:23","synthesized":"Are they ministers of Christ? (I speak as a fool) I am more; in labours more abundant, in stripes above measure, in prisons more frequent, in deaths oft.","sources":{"KJV":{"text":"Are they ministers of Christ? (I speak as a fool) I am more; in labours more abundant, in stripes above measure, in prisons more frequent, in deaths oft."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"Of the Jews five times received I forty stripes save one.","ref":"2 Corinthians 11:24","synthesized":"Of the Jews five times received I forty stripes save one.","sources":{"KJV":{"text":"Of the Jews five times received I forty stripes save one."}},"definableWords":["one"],"peopleInVerse":[]},"25":{"text":"Thrice was I beaten with rods, once was I stoned, thrice I suffered shipwreck, a night and a day I have been in the deep;","ref":"2 Corinthians 11:25","synthesized":"Thrice was I beaten with rods, once was I stoned, thrice I suffered shipwreck, a night and a day I have been in the deep;","sources":{"KJV":{"text":"Thrice was I beaten with rods, once was I stoned, thrice I suffered shipwreck, a night and a day I have been in the deep;"}},"definableWords":["night","day","deep"],"peopleInVerse":[]},"26":{"text":"In journeyings often, in perils of waters, in perils of robbers, in perils by mine own countrymen, in perils by the heathen, in perils in the city, in perils in the wilderness, in perils in the sea, in perils among false brethren;","ref":"2 Corinthians 11:26","synthesized":"In journeyings often, in perils of waters, in perils of robbers, in perils by mine own countrymen, in perils by the heathen, in perils in the city, in perils in the wilderness, in perils in the sea, in perils among false brethren;","sources":{"KJV":{"text":"In journeyings often, in perils of waters, in perils of robbers, in perils by mine own countrymen, in perils by the heathen, in perils in the city, in perils in the wilderness, in perils in the sea, in perils among false brethren;"}},"definableWords":["waters","sea","brethren"],"peopleInVerse":[]},"27":{"text":"In weariness and painfulness, in watchings often, in hunger and thirst, in fastings often, in cold and nakedness.","ref":"2 Corinthians 11:27","synthesized":"In weariness and painfulness, in watchings often, in hunger and thirst, in fastings often, in cold and nakedness.","sources":{"KJV":{"text":"In weariness and painfulness, in watchings often, in hunger and thirst, in fastings often, in cold and nakedness."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"Beside those things that are without, that which cometh upon me daily, the care of all the churches.","ref":"2 Corinthians 11:28","synthesized":"Beside those things that are without, that which cometh upon me daily, the care of all the churches.","sources":{"KJV":{"text":"Beside those things that are without, that which cometh upon me daily, the care of all the churches."}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"Who is weak, and I am not weak? who is offended, and I burn not?","ref":"2 Corinthians 11:29","synthesized":"Who is weak, and I am not weak? who is offended, and I burn not?","sources":{"KJV":{"text":"Who is weak, and I am not weak? who is offended, and I burn not?"}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"If I must needs glory, I will glory of the things which concern mine infirmities.","ref":"2 Corinthians 11:30","synthesized":"If I must needs glory, I will glory of the things which concern mine infirmities.","sources":{"KJV":{"text":"If I must needs glory, I will glory of the things which concern mine infirmities."}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"The God and Father of our Lord Jesus Christ, which is blessed for evermore, knoweth that I lie not.","ref":"2 Corinthians 11:31","synthesized":"The God and Father of our Lord Jesus Christ, which is blessed for evermore, knoweth that I lie not.","sources":{"KJV":{"text":"The God and Father of our Lord Jesus Christ, which is blessed for evermore, knoweth that I lie not."}},"definableWords":["God","father","Lord","blessed"],"peopleInVerse":["Jesus"]},"32":{"text":"In Damascus the governor under Aretas the king kept the city of the Damascenes with a garrison, desirous to apprehend me:","ref":"2 Corinthians 11:32","synthesized":"In Damascus the governor under Aretas the king kept the city of the Damascenes with a garrison, desirous to apprehend me:","sources":{"KJV":{"text":"In Damascus the governor under Aretas the king kept the city of the Damascenes with a garrison, desirous to apprehend me:"}},"definableWords":["king"],"peopleInVerse":[]},"33":{"text":"And through a window in a basket was I let down by the wall, and escaped his hands.","ref":"2 Corinthians 11:33","synthesized":"And through a window in a basket was I let down by the wall, and escaped his hands.","sources":{"KJV":{"text":"And through a window in a basket was I let down by the wall, and escaped his hands."}},"definableWords":[],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"MY GRACE IS SUFFICIENT","verses":{"1":{"text":"It is not expedient for me doubtless to glory. I will come to visions and revelations of the Lord.","ref":"2 Corinthians 12:1","synthesized":"It is not expedient for me doubtless to glory. I will come to visions and revelations of the Lord.","sources":{"KJV":{"text":"It is not expedient for me doubtless to glory. I will come to visions and revelations of the Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"2":{"text":"I knew a man in Christ above fourteen years ago, (whether in the body, I cannot tell; or whether out of the body, I cannot tell: God knoweth;) such an one caught up to the third heaven.","ref":"2 Corinthians 12:2","synthesized":"I knew a man in Christ above fourteen years ago, (whether in the body, I cannot tell; or whether out of the body, I cannot tell: God knoweth;) such an one caught up to the third heaven.","sources":{"KJV":{"text":"I knew a man in Christ above fourteen years ago, (whether in the body, I cannot tell; or whether out of the body, I cannot tell: God knoweth;) such an one caught up to the third heaven."}},"definableWords":["man","years","or","God","one","heaven"],"peopleInVerse":[]},"3":{"text":"And I knew such a man, (whether in the body, or out of the body, I cannot tell: God knoweth;)","ref":"2 Corinthians 12:3","synthesized":"And I knew such a man, (whether in the body, or out of the body, I cannot tell: God knoweth;)","sources":{"KJV":{"text":"And I knew such a man, (whether in the body, or out of the body, I cannot tell: God knoweth;)"}},"definableWords":["man","or","God"],"peopleInVerse":[]},"4":{"text":"How that he was caught up into paradise, and heard unspeakable words, which it is not lawful for a man to utter.","ref":"2 Corinthians 12:4","synthesized":"How that he was caught up into paradise, and heard unspeakable words, which it is not lawful for a man to utter.","sources":{"KJV":{"text":"How that he was caught up into paradise, and heard unspeakable words, which it is not lawful for a man to utter."}},"definableWords":["man"],"peopleInVerse":[]},"5":{"text":"Of such an one will I glory: yet of myself I will not glory, but in mine infirmities.","ref":"2 Corinthians 12:5","synthesized":"Of such an one will I glory: yet of myself I will not glory, but in mine infirmities.","sources":{"KJV":{"text":"Of such an one will I glory: yet of myself I will not glory, but in mine infirmities."}},"definableWords":["one"],"peopleInVerse":[]},"6":{"text":"For though I would desire to glory, I shall not be a fool; for I will say the truth: but now I forbear, lest any man should think of me above that which he seeth me to be, or that he heareth of me.","ref":"2 Corinthians 12:6","synthesized":"For though I would desire to glory, I shall not be a fool; for I will say the truth: but now I forbear, lest any man should think of me above that which he seeth me to be, or that he heareth of me.","sources":{"KJV":{"text":"For though I would desire to glory, I shall not be a fool; for I will say the truth: but now I forbear, lest any man should think of me above that which he seeth me to be, or that he heareth of me."}},"definableWords":["man","or"],"peopleInVerse":[]},"7":{"text":"And lest I should be exalted above measure through the abundance of the revelations, there was given to me a thorn in the flesh, the messenger of Satan to buffet me, lest I should be exalted above measure.","ref":"2 Corinthians 12:7","synthesized":"And lest I should be exalted above measure through the abundance of the revelations, there was given to me a thorn in the flesh, the messenger of Satan to buffet me, lest I should be exalted above measure.","sources":{"KJV":{"text":"And lest I should be exalted above measure through the abundance of the revelations, there was given to me a thorn in the flesh, the messenger of Satan to buffet me, lest I should be exalted above measure."}},"definableWords":["flesh"],"peopleInVerse":[]},"8":{"text":"For this thing I besought the Lord thrice, that it might depart from me.","ref":"2 Corinthians 12:8","synthesized":"For this thing I besought the Lord thrice, that it might depart from me.","sources":{"KJV":{"text":"For this thing I besought the Lord thrice, that it might depart from me."}},"definableWords":["Lord"],"peopleInVerse":[]},"9":{"text":"And he said unto me, My grace is sufficient for thee: for my strength is made perfect in weakness. Most gladly therefore will I rather glory in my infirmities, that the power of Christ may rest upon me.","ref":"2 Corinthians 12:9","synthesized":"And he said unto me, My grace is sufficient for thee: for my strength is made perfect in weakness. Most gladly therefore will I rather glory in my infirmities, that the power of Christ may rest upon me.","sources":{"KJV":{"text":"And he said unto me, My grace is sufficient for thee: for my strength is made perfect in weakness. Most gladly therefore will I rather glory in my infirmities, that the power of Christ may rest upon me."}},"definableWords":["made","rest"],"peopleInVerse":[]},"10":{"text":"Therefore I take pleasure in infirmities, in reproaches, in necessities, in persecutions, in distresses for Christ’s sake: for when I am weak, then am I strong.","ref":"2 Corinthians 12:10","synthesized":"Therefore I take pleasure in infirmities, in reproaches, in necessities, in persecutions, in distresses for Christ’s sake: for when I am weak, then am I strong.","sources":{"KJV":{"text":"Therefore I take pleasure in infirmities, in reproaches, in necessities, in persecutions, in distresses for Christ’s sake: for when I am weak, then am I strong."}},"definableWords":["strong"],"peopleInVerse":[]},"11":{"text":"I am become a fool in glorying; ye have compelled me: for I ought to have been commended of you: for in nothing am I behind the very chiefest apostles, though I be nothing.","ref":"2 Corinthians 12:11","synthesized":"I am become a fool in glorying; ye have compelled me: for I ought to have been commended of you: for in nothing am I behind the very chiefest apostles, though I be nothing.","sources":{"KJV":{"text":"I am become a fool in glorying; ye have compelled me: for I ought to have been commended of you: for in nothing am I behind the very chiefest apostles, though I be nothing."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Truly the signs of an apostle were wrought among you in all patience, in signs, and wonders, and mighty deeds.","ref":"2 Corinthians 12:12","synthesized":"Truly the signs of an apostle were wrought among you in all patience, in signs, and wonders, and mighty deeds.","sources":{"KJV":{"text":"Truly the signs of an apostle were wrought among you in all patience, in signs, and wonders, and mighty deeds."}},"definableWords":["mighty"],"peopleInVerse":[]},"13":{"text":"For what is it wherein ye were inferior to other churches, except it be that I myself was not burdensome to you? forgive me this wrong.","ref":"2 Corinthians 12:13","synthesized":"For what is it wherein ye were inferior to other churches, except it be that I myself was not burdensome to you? forgive me this wrong.","sources":{"KJV":{"text":"For what is it wherein ye were inferior to other churches, except it be that I myself was not burdensome to you? forgive me this wrong."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Behold, the third time I am ready to come to you; and I will not be burdensome to you: for I seek not yours, but you: for the children ought not to lay up for the parents, but the parents for the children.","ref":"2 Corinthians 12:14","synthesized":"Behold, the third time I am ready to come to you; and I will not be burdensome to you: for I seek not yours, but you: for the children ought not to lay up for the parents, but the parents for the children.","sources":{"KJV":{"text":"Behold, the third time I am ready to come to you; and I will not be burdensome to you: for I seek not yours, but you: for the children ought not to lay up for the parents, but the parents for the children."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And I will very gladly spend and be spent for you; though the more abundantly I love you, the less I be loved.","ref":"2 Corinthians 12:15","synthesized":"And I will very gladly spend and be spent for you; though the more abundantly I love you, the less I be loved.","sources":{"KJV":{"text":"And I will very gladly spend and be spent for you; though the more abundantly I love you, the less I be loved."}},"definableWords":["love"],"peopleInVerse":[]},"16":{"text":"But be it so, I did not burden you: nevertheless, being crafty, I caught you with guile.","ref":"2 Corinthians 12:16","synthesized":"But be it so, I did not burden you: nevertheless, being crafty, I caught you with guile.","sources":{"KJV":{"text":"But be it so, I did not burden you: nevertheless, being crafty, I caught you with guile."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Did I make a gain of you by any of them whom I sent unto you?","ref":"2 Corinthians 12:17","synthesized":"Did I make a gain of you by any of them whom I sent unto you?","sources":{"KJV":{"text":"Did I make a gain of you by any of them whom I sent unto you?"}},"definableWords":["make"],"peopleInVerse":[]},"18":{"text":"I desired Titus, and with him I sent a brother. Did Titus make a gain of you? walked we not in the same spirit? walked we not in the same steps?","ref":"2 Corinthians 12:18","synthesized":"I desired Titus, and with him I sent a brother. Did Titus make a gain of you? walked we not in the same spirit? walked we not in the same steps?","sources":{"KJV":{"text":"I desired Titus, and with him I sent a brother. Did Titus make a gain of you? walked we not in the same spirit? walked we not in the same steps?"}},"definableWords":["brother","make","walked","spirit"],"peopleInVerse":[]},"19":{"text":"Again, think ye that we excuse ourselves unto you? we speak before God in Christ: but we do all things, dearly beloved, for your edifying.","ref":"2 Corinthians 12:19","synthesized":"Again, think ye that we excuse ourselves unto you? we speak before God in Christ: but we do all things, dearly beloved, for your edifying.","sources":{"KJV":{"text":"Again, think ye that we excuse ourselves unto you? we speak before God in Christ: but we do all things, dearly beloved, for your edifying."}},"definableWords":["God"],"peopleInVerse":[]},"20":{"text":"For I fear, lest, when I come, I shall not find you such as I would, and that I shall be found unto you such as ye would not: lest there be debates, envyings, wraths, strifes, backbitings, whisperings, swellings, tumults:","ref":"2 Corinthians 12:20","synthesized":"For I fear, lest, when I come, I shall not find you such as I would, and that I shall be found unto you such as ye would not: lest there be debates, envyings, wraths, strifes, backbitings, whisperings, swellings, tumults:","sources":{"KJV":{"text":"For I fear, lest, when I come, I shall not find you such as I would, and that I shall be found unto you such as ye would not: lest there be debates, envyings, wraths, strifes, backbitings, whisperings, swellings, tumults:"}},"definableWords":["fear"],"peopleInVerse":[]},"21":{"text":"And lest, when I come again, my God will humble me among you, and that I shall bewail many which have sinned already, and have not repented of the uncleanness and fornication and lasciviousness which they have committed.","ref":"2 Corinthians 12:21","synthesized":"And lest, when I come again, my God will humble me among you, and that I shall bewail many which have sinned already, and have not repented of the uncleanness and fornication and lasciviousness which they have committed.","sources":{"KJV":{"text":"And lest, when I come again, my God will humble me among you, and that I shall bewail many which have sinned already, and have not repented of the uncleanness and fornication and lasciviousness which they have committed."}},"definableWords":["God"],"peopleInVerse":[]}}},"13":{"chapter":"13","title":"EXAMINE YOURSELVES","verses":{"1":{"text":"This is the third time I am coming to you. In the mouth of two or three witnesses shall every word be established.","ref":"2 Corinthians 13:1","synthesized":"This is the third time I am coming to you. In the mouth of two or three witnesses shall every word be established.","sources":{"KJV":{"text":"This is the third time I am coming to you. In the mouth of two or three witnesses shall every word be established."}},"definableWords":["or","word"],"peopleInVerse":[]},"2":{"text":"I told you before, and foretell you, as if I were present, the second time; and being absent now I write to them which heretofore have sinned, and to all other, that, if I come again, I will not spare:","ref":"2 Corinthians 13:2","synthesized":"I told you before, and foretell you, as if I were present, the second time; and being absent now I write to them which heretofore have sinned, and to all other, that, if I come again, I will not spare:","sources":{"KJV":{"text":"I told you before, and foretell you, as if I were present, the second time; and being absent now I write to them which heretofore have sinned, and to all other, that, if I come again, I will not spare:"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Since ye seek a proof of Christ speaking in me, which to you-ward is not weak, but is mighty in you.","ref":"2 Corinthians 13:3","synthesized":"Since ye seek a proof of Christ speaking in me, which to you-ward is not weak, but is mighty in you.","sources":{"KJV":{"text":"Since ye seek a proof of Christ speaking in me, which to you-ward is not weak, but is mighty in you."}},"definableWords":["mighty"],"peopleInVerse":[]},"4":{"text":"For though he was crucified through weakness, yet he liveth by the power of God. For we also are weak in him, but we shall live with him by the power of God toward you.","ref":"2 Corinthians 13:4","synthesized":"For though he was crucified through weakness, yet he liveth by the power of God. For we also are weak in him, but we shall live with him by the power of God toward you.","sources":{"KJV":{"text":"For though he was crucified through weakness, yet he liveth by the power of God. For we also are weak in him, but we shall live with him by the power of God toward you."}},"definableWords":["God","live"],"peopleInVerse":[]},"5":{"text":"Examine yourselves, whether ye be in the faith; prove your own selves. Know ye not your own selves, how that Jesus Christ is in you, except ye be reprobates?","ref":"2 Corinthians 13:5","synthesized":"Examine yourselves, whether ye be in the faith; prove your own selves. Know ye not your own selves, how that Jesus Christ is in you, except ye be reprobates?","sources":{"KJV":{"text":"Examine yourselves, whether ye be in the faith; prove your own selves. Know ye not your own selves, how that Jesus Christ is in you, except ye be reprobates?"}},"definableWords":["faith"],"peopleInVerse":["Jesus"]},"6":{"text":"But I trust that ye shall know that we are not reprobates.","ref":"2 Corinthians 13:6","synthesized":"But I trust that ye shall know that we are not reprobates.","sources":{"KJV":{"text":"But I trust that ye shall know that we are not reprobates."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Now I pray to God that ye do no evil; not that we should appear approved, but that ye should do that which is honest, though we be as reprobates.","ref":"2 Corinthians 13:7","synthesized":"Now I pray to God that ye do no evil; not that we should appear approved, but that ye should do that which is honest, though we be as reprobates.","sources":{"KJV":{"text":"Now I pray to God that ye do no evil; not that we should appear approved, but that ye should do that which is honest, though we be as reprobates."}},"definableWords":["God","evil"],"peopleInVerse":[]},"8":{"text":"For we can do nothing against the truth, but for the truth.","ref":"2 Corinthians 13:8","synthesized":"For we can do nothing against the truth, but for the truth.","sources":{"KJV":{"text":"For we can do nothing against the truth, but for the truth."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"For we are glad, when we are weak, and ye are strong: and this also we wish, even your perfection.","ref":"2 Corinthians 13:9","synthesized":"For we are glad, when we are weak, and ye are strong: and this also we wish, even your perfection.","sources":{"KJV":{"text":"For we are glad, when we are weak, and ye are strong: and this also we wish, even your perfection."}},"definableWords":["strong"],"peopleInVerse":[]},"10":{"text":"Therefore I write these things being absent, lest being present I should use sharpness, according to the power which the Lord hath given me to edification, and not to destruction.","ref":"2 Corinthians 13:10","synthesized":"Therefore I write these things being absent, lest being present I should use sharpness, according to the power which the Lord hath given me to edification, and not to destruction.","sources":{"KJV":{"text":"Therefore I write these things being absent, lest being present I should use sharpness, according to the power which the Lord hath given me to edification, and not to destruction."}},"definableWords":["Lord"],"peopleInVerse":[]},"11":{"text":"Finally, brethren, farewell. Be perfect, be of good comfort, be of one mind, live in peace; and the God of love and peace shall be with you.","ref":"2 Corinthians 13:11","synthesized":"Finally, brethren, farewell. Be perfect, be of good comfort, be of one mind, live in peace; and the God of love and peace shall be with you.","sources":{"KJV":{"text":"Finally, brethren, farewell. Be perfect, be of good comfort, be of one mind, live in peace; and the God of love and peace shall be with you."}},"definableWords":["brethren","good","one","live","peace","God","love"],"peopleInVerse":[]},"12":{"text":"Greet one another with an holy kiss.","ref":"2 Corinthians 13:12","synthesized":"Greet one another with an holy kiss.","sources":{"KJV":{"text":"Greet one another with an holy kiss."}},"definableWords":["one"],"peopleInVerse":[]},"13":{"text":"All the saints salute you.","ref":"2 Corinthians 13:13","synthesized":"All the saints salute you.","sources":{"KJV":{"text":"All the saints salute you."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"The grace of the Lord Jesus Christ, and the love of God, and the communion of the Holy Ghost, be with you all. Amen.","ref":"2 Corinthians 13:14","synthesized":"The grace of the Lord Jesus Christ, and the love of God, and the communion of the Holy Ghost, be with you all. Amen.","sources":{"KJV":{"text":"The grace of the Lord Jesus Christ, and the love of God, and the communion of the Holy Ghost, be with you all. Amen."}},"definableWords":["Lord","love","God"],"peopleInVerse":["Jesus"]}}}};